// н”„л Ҳмһ„ м •л ¬ мғҒмҲҳ л°Ҹ н•ЁмҲҳ (лІӨм№ҳл§ҲнӮ№ мҪ”л“ң л°©мӢқ - м „мІҙ нҢҢмқјм—җм„ң кіөмң )
const VIDEO_FPS = 25
const FRAME_DURATION = 1.0 / VIDEO_FPS // 0.04мҙҲ
const SUBTITLE_SAFETY_MARGIN = 0.02 // 20ms м•Ҳм „ л§Ҳм§„ (мһҘл©ҙ м „нҷҳ мӢң мһҗл§ү мһҳлҰј л°©м§Җ)

// н”„л Ҳмһ„ м •л ¬ н•ЁмҲҳ: мӢңк°„мқ„ 0.04мҙҲ лӢЁмң„лЎң мҳ¬лҰј мІҳлҰ¬
const alignToFrame = (time: number): number => {
  // м•„мЈј лҜём„ён•ң мҳӨм°Ё(1ms лҜёл§Ң)лҠ” л¬ҙмӢңн•ҳкі  мҳ¬лҰј мІҳлҰ¬
  return Math.ceil((time - 0.0001) / FRAME_DURATION) * FRAME_DURATION
}

