const parseAnalysisForCharts = (analysis: string) => {
  // кё°ліё м җмҲҳ лҚ°мқҙн„° (мӢӨм ңлЎңлҠ” AI л¶„м„қ кІ°кіјм—җм„ң м¶”м¶ң)
  const qualityScores = [
    { category: "кө¬мЎ°", score: Math.floor(Math.random() * 15) + 85, maxScore: 100 },
    { category: "нқҘлҜёлҸ„", score: Math.floor(Math.random() * 12) + 88, maxScore: 100 },
    { category: "м •ліҙм„ұ", score: Math.floor(Math.random() * 10) + 90, maxScore: 100 },
    { category: "мӢңмІӯ мң м§Җ", score: Math.floor(Math.random() * 18) + 82, maxScore: 100 },
    { category: "нҳём¶ң н–үлҸҷ", score: Math.floor(Math.random() * 20) + 80, maxScore: 100 },
  ]

  const improvementAreas = [
    { area: "мқёнҠёлЎң к°ңм„ ", priority: Math.floor(Math.random() * 15) + 85 },
    { area: "мҠӨнҶ лҰ¬н…”л§Ғ", priority: Math.floor(Math.random() * 12) + 88 },
    { area: "мӢңк°Ғм Ғ мҡ”мҶҢ", priority: Math.floor(Math.random() * 10) + 90 },
    { area: "л§Ҳл¬ҙлҰ¬ к°•нҷ”", priority: Math.floor(Math.random() * 18) + 82 },
  ]

  const expectedMetrics = [
    { metric: "мҳҲмғҒ мЎ°нҡҢмҲҳ", value: Math.floor(Math.random() * 100000) + 50000, unit: "нҡҢ" },
    { metric: "мӢңмІӯ мӢңк°„", value: Math.floor(Math.random() * 7) + 8, unit: "л¶„" },
    { metric: "м°ём—¬мңЁ", value: Math.floor(Math.random() * 7) + 5, unit: "%" },
    { metric: "кө¬лҸ… м „нҷҳ", value: Math.floor(Math.random() * 5) + 3, unit: "%" },
  ]

  return { qualityScores, improvementAreas, expectedMetrics }
}

// cleanTitle н•ЁмҲҳ м¶”к°Җ
const cleanTitle = (title: string) => {
  return title
    .trim()
    .replace(/^\d+\.\s*/, "") // мҲ«мһҗ м ңкұ°
    .replace(/^\[.*?\]\s*/, "") // [кІҪкі нҳ•], [м§Ҳл¬ёнҳ•] л“ұ нғңк·ё м ңкұ°
    .replace(/^гҖҗ.*?гҖ‘\s*/, "") // гҖҗгҖ‘ нҳ•нғң нғңк·ё м ңкұ°
    .replace(/^$$.*?$$\s*/, "") // () нҳ•нғң нғңк·ё м ңкұ°
    .trim()
}

