  // API нӮӨ к°Җм ёмҳӨкё° н—¬нҚј н•ЁмҲҳ
  const getApiKey = (keyName?: string) => {
    if (typeof window === "undefined") return undefined
    if (keyName) {
      return localStorage.getItem(keyName) || undefined
    }
    return localStorage.getItem("openai_api_key") || undefined
  }
  
  // Gemini API нӮӨ к°Җм ёмҳӨкё° н—¬нҚј н•ЁмҲҳ
  const getGeminiApiKey = () => {
    if (typeof window === "undefined") return undefined
    return localStorage.getItem("gemini_api_key") || undefined
  }
  
  // м•ҢлҰјмқҢ мһ¬мғқ н•ЁмҲҳ (лқ л§Ғ мҶҢлҰ¬)
  const playNotificationSound = () => {
    try {
      // Web Audio APIлҘј мӮ¬мҡ©н•ҳм—¬ к°„лӢЁн•ң beep мҶҢлҰ¬ мғқм„ұ
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)()
      const oscillator = audioContext.createOscillator()
      const gainNode = audioContext.createGain()
      
      oscillator.connect(gainNode)
      gainNode.connect(audioContext.destination)
      
      // 800Hz мЈјнҢҢмҲҳлЎң 0.2мҙҲ лҸҷм•Ҳ мһ¬мғқ
      oscillator.frequency.value = 800
      oscillator.type = 'sine'
      
      // нҺҳмқҙл“ң м•„мӣғ нҡЁкіј
      gainNode.gain.setValueAtTime(0.3, audioContext.currentTime)
      gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.2)
      
      oscillator.start(audioContext.currentTime)
      oscillator.stop(audioContext.currentTime + 0.2)
    } catch (error) {
      // мҳӨл””мҳӨ мһ¬мғқ мӢӨнҢЁ мӢң л¬ҙмӢң (мқјл¶Җ лёҢлқјмҡ°м Җм—җм„ң мӮ¬мҡ©мһҗ мқён„°лһҷм…ҳ м—ҶмқҙлҠ” мһ¬мғқ л¶Ҳк°Җ)
      console.log("[м•ҢлҰјмқҢ] мһ¬мғқ мӢӨнҢЁ (л¬ҙмӢңлҗЁ):", error)
    }
  }
  
  // мӮ¬мҡ©мһҗ ID к°Җм ёмҳӨкё° (м№ҙм№ҙмҳӨ лЎңк·ёмқё мӮ¬мҡ©мһҗ м •ліҙ)
