            console.log("[мһҗлҸҷнҷ”] AI мҚёл„Өмқј мғқм„ұ мӢңмһ‘, мЈјм ң:", topicToUse, "мқҙлҜём§Җ мҠӨнғҖмқј:", imageStyle, "м»ӨмҠӨн…Җ л¬ёкө¬:", thumbnailCustomText, "л¬ёкө¬ м—Ҷмқҙ:", thumbnailWithoutText, "мҚёл„Өмқј мҠӨнғҖмқј:", thumbnailStyle, "мәҗлҰӯн„°:", characterDescription)
