      const errorMessage = error instanceof Error ? error.message : "м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ."
      alert(`AI мҚёл„Өмқј мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ: ${errorMessage}`)
