  // лҢҖліёмқ„ м Ғм Ҳн•ң кёёмқҙмқҳ л¬ёмһҘ к·ёлЈ№мңјлЎң лӮҳлҲ„лҠ” н•ЁмҲҳ
  // мғҲлЎңмҡҙ мһҘл©ҙ л¶„н•ҙ нҳ•мӢқмқ„ нҢҢмӢұн•ҳм—¬ scriptLinesлЎң ліҖнҷҳн•ҳлҠ” н•ЁмҲҳ
  const parseSceneBlocks = (sceneText: string): Array<{ id: number; text: string }> => {
    if (!sceneText || sceneText.trim().length === 0) {
      return []
    }

    const lines: Array<{ id: number; text: string }> = []
    let currentId = 1

    // м”¬ лё”лЎқмқ„ м°ҫкё° мң„н•ң м •к·ңмӢқ
    // нҳ•мӢқ: м”¬ {number}\n[мһҘл©ҙ 1]\n(н…ҚмҠӨнҠё)\n[мһҘл©ҙ 2]\n(н…ҚмҠӨнҠё)...
    // н”Ңлһҳк·ё 's'лҠ” ES2018 мқҙмғҒмқҙ н•„мҡ”н•ҳлҜҖлЎң м ңкұ°н•ҳм—¬ нҳёнҷҳм„ұ лҶ’мһ„
    const sceneRegex = /м”¬\s+(\d+)\s*\n\[мһҘл©ҙ\s+(\d+)\]\s*\n([^[]+?)(?=\[мһҘл©ҙ\s+\d+\]|м”¬\s+\d+|$)/g

    let match
    while ((match = sceneRegex.exec(sceneText)) !== null) {
      const sceneNum = match[1]
      const shotNum = match[2]
      const shotText = match[3].trim()

      if (shotText) {
        lines.push({
          id: currentId++,
          text: shotText,
        })
      }
    }

    // м •к·ңмӢқмңјлЎң л§Өм№ӯлҗҳм§Җ м•ҠмқҖ кІҪмҡ°, к°„лӢЁн•ң нҢҢмӢұ мӢңлҸ„
    if (lines.length === 0) {
      // [мһҘл©ҙ N] нҳ•мӢқмңјлЎң м§Ғм ‘ нҢҢмӢұ
      const shotRegex = /\[мһҘл©ҙ\s+\d+\]\s*\n([^\[]+?)(?=\[мһҘл©ҙ\s+\d+\]|м”¬\s+\d+|$)/g
      let shotMatch
      while ((shotMatch = shotRegex.exec(sceneText)) !== null) {
        const shotText = shotMatch[1].trim()
        if (shotText) {
          lines.push({
            id: currentId++,
            text: shotText,
          })
        }
      }
    }

    return lines
  }

  // Gemini APIлҘј мӮ¬мҡ©н•ҳм—¬ мқҳлҜё лӢЁмң„ м„ёк·ёлЁјнҠё мғқм„ұ
  const generateSemanticSegments = async (text: string, geminiApiKey: string): Promise<string[]> => {
    try {
      // м„ңлІ„ API лқјмҡ°нҠёлҘј нҶөн•ҙ нҳём¶ң (API нӮӨ л…ём¶ң л°©м§Җ)
      const response = await fetch("/api/gemini/generate-content", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          model: "gemini-2.0-flash-exp",
          contents: [{
            parts: [{
              text: `лӢӨмқҢ н…ҚмҠӨнҠёлҘј мқҳлҜё лӢЁмң„лЎң л¶„н• н•ҙмЈјм„ёмҡ”. к°Ғ мқҳлҜё лӢЁмң„лҠ” лҸ…лҰҪм Ғмқё л¬ёмһҘмқҙлӮҳ кө¬м Ҳмқҙм–ҙм•ј н•©лӢҲлӢӨ. кІ°кіјлҠ” JSON л°°м—ҙ нҳ•мӢқмңјлЎң л°ҳнҷҳн•ҙмЈјм„ёмҡ”.\n\nн…ҚмҠӨнҠё: ${text}\n\nкІ°кіј нҳ•мӢқ: ["мқҳлҜё лӢЁмң„ 1", "мқҳлҜё лӢЁмң„ 2", ...]`
            }]
          }],
          generationConfig: {
            temperature: 0.3,
            maxOutputTokens: 2000,
          },
        }),
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(`Gemini API нҳём¶ң мӢӨнҢЁ: ${response.status} - ${errorData.error || errorData.details || "м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳ"}`)
      }

      const data = await response.json()
      const resultText = data.candidates?.[0]?.content?.parts?.[0]?.text || ""
      
      // JSON л°°м—ҙ м¶”м¶ң
      const jsonMatch = resultText.match(/\[[\s\S]*\]/)
      if (jsonMatch) {
        const segments = JSON.parse(jsonMatch[0])
        return Array.isArray(segments) ? segments : [text]
      }
      
      // JSONмқҙ м—Ҷмңјл©ҙ мӨ„л°”кҝҲмңјлЎң л¶„н• 
      return resultText.split('\n').filter((s: string) => s.trim().length > 0)
    } catch (error) {
      console.error("[мқҳлҜё лӢЁмң„ м„ёк·ёлЁјнҠё мғқм„ұ мӢӨнҢЁ]:", error)
      // мӢӨнҢЁ мӢң кё°ліё л¶„н•  (л¬ёмһҘ лӢЁмң„)
      return text.split(/[.!?гҖӮпјҒпјҹ]\s*/).filter(s => s.trim().length > 0)
    }
  }

  // AudioBufferлҘј WAV BlobмңјлЎң ліҖнҷҳн•ҳлҠ” н—¬нҚј н•ЁмҲҳ
  const audioBufferToBlob = async (audioBuffer: AudioBuffer): Promise<Blob> => {
    const numberOfChannels = audioBuffer.numberOfChannels
    const sampleRate = audioBuffer.sampleRate
    const length = audioBuffer.length
    
    // мқён„°лҰ¬лёҢлҗң лҚ°мқҙн„° мғқм„ұ
    const resultBuffer = new Float32Array(length * numberOfChannels)
    let offset = 0
    for (let channel = 0; channel < numberOfChannels; channel++) {
      resultBuffer.set(audioBuffer.getChannelData(channel), offset)
      offset += length
    }
    
    // WAV мқёмҪ”л”©
    const wavBuffer = encodeWAV(resultBuffer, numberOfChannels, sampleRate)
    return new Blob([wavBuffer], { type: 'audio/wav' })
  }

  // Float32ArrayлҘј WAV нҳ•мӢқмңјлЎң мқёмҪ”л”©
  const encodeWAV = (samples: Float32Array, numChannels: number, sampleRate: number): ArrayBuffer => {
    const length = samples.length
    const buffer = new ArrayBuffer(44 + length * 2)
    const view = new DataView(buffer)
    
    // WAV н—ӨлҚ” мһ‘м„ұ
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        view.setUint8(offset + i, string.charCodeAt(i))
      }
    }
    
    writeString(0, 'RIFF')
    view.setUint32(4, 36 + length * 2, true)
    writeString(8, 'WAVE')
    writeString(12, 'fmt ')
    view.setUint32(16, 16, true)
    view.setUint16(20, 1, true)
    view.setUint16(22, numChannels, true)
    view.setUint32(24, sampleRate, true)
    view.setUint32(28, sampleRate * numChannels * 2, true)
    view.setUint16(32, numChannels * 2, true)
    view.setUint16(34, 16, true)
    writeString(36, 'data')
    view.setUint32(40, length * 2, true)
    
    // мғҳн”Ң лҚ°мқҙн„° ліҖнҷҳ (Float32 -> Int16)
    let offset = 44
    for (let i = 0; i < length; i++) {
      const s = Math.max(-1, Math.min(1, samples[i]))
      view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true)
      offset += 2
    }
    
    return buffer
  }

  // wordTimingsлҘј alignment нҳ•мӢқмңјлЎң ліҖнҷҳ (Whisper align API кІ°кіјлҘј ElevenLabs нҳ•мӢқмңјлЎң ліҖнҷҳ)
  const convertWordTimingsToAlignment = (
    wordTimings: Array<{ word: string; start: number; end: number; confidence?: number }>,
    text: string
  ): any => {
    if (!wordTimings || wordTimings.length === 0) {
      return null
    }

    // н…ҚмҠӨнҠёлҘј л¬ёмһҗ л°°м—ҙлЎң ліҖнҷҳ
    const characters: string[] = []
    const characterStartTimes: number[] = []
    const characterEndTimes: number[] = []

    let textIndex = 0
    for (const wordTiming of wordTimings) {
      const word = wordTiming.word
      const wordStart = wordTiming.start
      const wordEnd = wordTiming.end
      const wordDuration = wordEnd - wordStart

      // лӢЁм–ҙмқҳ к°Ғ л¬ёмһҗм—җ мӢңк°„ н• лӢ№
      for (let i = 0; i < word.length; i++) {
        const char = word[i]
        const charRatio = i / word.length
        const charStart = wordStart + (wordDuration * charRatio)
        const charEnd = i === word.length - 1 
          ? wordEnd 
          : wordStart + (wordDuration * ((i + 1) / word.length))

        characters.push(char)
        characterStartTimes.push(Number.parseFloat(charStart.toFixed(6))) // мҶҢмҲҳм җ 6мһҗлҰ¬к№Ңм§Җ
        characterEndTimes.push(Number.parseFloat(charEnd.toFixed(6)))
        textIndex++
      }

      // лӢЁм–ҙ л’Өм—җ кіөл°ұ м¶”к°Җ (л§Ҳм§Җл§ү лӢЁм–ҙк°Җ м•„лӢҲл©ҙ)
      if (wordTiming !== wordTimings[wordTimings.length - 1]) {
        const spaceStart = wordEnd
        const spaceEnd = wordTiming !== wordTimings[wordTimings.length - 1] 
          ? (wordTimings[wordTimings.indexOf(wordTiming) + 1]?.start || wordEnd)
          : wordEnd

        characters.push(" ")
        characterStartTimes.push(Number.parseFloat(spaceStart.toFixed(6)))
        characterEndTimes.push(Number.parseFloat(Math.min(spaceEnd, wordEnd + 0.1).toFixed(6)))
        textIndex++
      }
    }

    return {
      characters: characters.join(""),
      character_start_times_seconds: characterStartTimes,
      character_end_times_seconds: characterEndTimes,
    }
  }

  // AlignmentмҷҖ м„ёк·ёлЁјнҠёлҘј л§Өм№ӯн•ҳм—¬ м •нҷ•н•ң мһҗл§ү нғҖмқҙл°Қ мғқм„ұ
  const alignmentToPhrases = (
    alignment: any,
    charLimit: number,
    semanticSegments: string[]
  ): Array<{ text: string; start: number; end: number }> => {
    if (!alignment || !alignment.characters || !alignment.character_start_times_seconds || !alignment.character_end_times_seconds) {
      // alignmentк°Җ м—Ҷмңјл©ҙ fallback
      return []
    }

    const characters = alignment.characters
    const startTimes = alignment.character_start_times_seconds
    const endTimes = alignment.character_end_times_seconds

    const phrases: Array<{ text: string; start: number; end: number }> = []
    let currentPhrase = ""
    let phraseStart = 0
    let phraseEnd = 0
    let charIndex = 0

    // semantic segmentsмҷҖ alignment л§Өм№ӯ
    for (const segment of semanticSegments) {
      const segmentStartChar = charIndex
      const segmentEndChar = charIndex + segment.length
      
      // м„ёк·ёлЁјнҠёмқҳ мӢңмһ‘/мў…лЈҢ л¬ёмһҗ мқёлҚұмҠӨ м°ҫкё°
      let segmentStartTime = 0
      let segmentEndTime = 0
      
      // м„ёк·ёлЁјнҠёмқҳ мІ« л¬ёмһҗмҷҖ л§Ҳм§Җл§ү л¬ёмһҗмқҳ мӢңк°„ м°ҫкё°
      for (let i = 0; i < characters.length; i++) {
        if (i >= segmentStartChar && i < segmentEndChar) {
          if (segmentStartTime === 0 && startTimes[i] !== undefined) {
            segmentStartTime = startTimes[i]
          }
          if (endTimes[i] !== undefined) {
            segmentEndTime = endTimes[i]
          }
        }
      }

      // м„ёк·ёлЁјнҠёлҘј charLimit лӢЁмң„лЎң лӮҳлҲ„кё°
      let currentLine = ""
      let lineStart = segmentStartTime
      let lineEnd = segmentStartTime

      for (let i = 0; i < segment.length; i++) {
        const char = segment[i]
        const charIdx = segmentStartChar + i
        
        if (charIdx < characters.length) {
          const charStart = startTimes[charIdx] || segmentStartTime
          const charEnd = endTimes[charIdx] || segmentEndTime
          
          const testLine = currentLine + char
          
          if (testLine.length > charLimit && currentLine.length > 0) {
            // нҳ„мһ¬ мӨ„ м ҖмһҘ
            phrases.push({
              text: currentLine.trim(),
              start: lineStart,
              end: lineEnd,
            })
            // мғҲ мӨ„ мӢңмһ‘
            currentLine = char
            lineStart = charStart
            lineEnd = charEnd
          } else {
            currentLine = testLine
            lineEnd = charEnd
          }
        } else {
          currentLine += char
        }
      }

      // л§Ҳм§Җл§ү мӨ„ м ҖмһҘ
      if (currentLine.trim().length > 0) {
        phrases.push({
          text: currentLine.trim(),
          start: lineStart,
          end: segmentEndTime > 0 ? segmentEndTime : lineEnd,
        })
      }

      charIndex = segmentEndChar
    }

    return phrases.length > 0 ? phrases : []
  }

  const splitScriptIntoLines = (scriptText: string, isRefined: boolean = false): Array<{ id: number; text: string }> => {
    if (!scriptText || scriptText.trim().length === 0) {
      return []
    }

    // м •көҗн•ң лҢҖліёмқҳ кІҪмҡ°: мқҳлҜё/мһҘл©ҙ лӢЁмң„лЎң лӮҳлүҳм–ҙ мһҲмңјлҜҖлЎң мӨ„л°”кҝҲмқ„ кё°мӨҖмңјлЎң мІҳлҰ¬
    if (isRefined) {
      // л№Ҳ мӨ„(мӨ„л°”кҝҲ 2к°ң мқҙмғҒ) лҳҗлҠ” лӢЁмқј мӨ„л°”кҝҲмқ„ кё°мӨҖмңјлЎң мқҳлҜё лӢЁмң„ л¶„лҰ¬
      const meaningUnits = scriptText.split(/\n\s*\n/).filter(unit => unit.trim().length > 0)
      
      const groupedLines: Array<{ id: number; text: string }> = []
      const TARGET_LINE_LENGTH = 60 // лӘ©н‘ң кёёмқҙ (10~15мҙҲ л¶„лҹү)
      const MIN_LINE_LENGTH = 35 // мөңмҶҢ кёёмқҙ
      const MAX_LINE_LENGTH = 90 // мөңлҢҖ кёёмқҙ
      
      for (const unit of meaningUnits) {
        const trimmedUnit = unit.trim().replace(/\n/g, " ") // лӢЁмқј мӨ„л°”кҝҲмқҖ кіөл°ұмңјлЎң ліҖнҷҳ
        const unitLength = trimmedUnit.length
        
        // мқҳлҜё лӢЁмң„к°Җ мқҙлҜё м Ғм Ҳн•ң кёёмқҙл©ҙ к·ёлҢҖлЎң мӮ¬мҡ©
        if (unitLength >= MIN_LINE_LENGTH && unitLength <= MAX_LINE_LENGTH) {
          groupedLines.push({
            id: groupedLines.length + 1,
            text: trimmedUnit,
          })
        }
        // мқҳлҜё лӢЁмң„к°Җ л„Ҳл¬ҙ м§§мңјл©ҙ лӢӨмқҢ лӢЁмң„мҷҖ н•©м№ҳкұ°лӮҳ к·ёлҢҖлЎң мӮ¬мҡ©
        else if (unitLength < MIN_LINE_LENGTH) {
          if (groupedLines.length > 0) {
            // мқҙм „ к·ёлЈ№м—җ н•©м№ҳкё°
            const lastIndex = groupedLines.length - 1
            const combined = groupedLines[lastIndex].text + " " + trimmedUnit
            if (combined.length <= MAX_LINE_LENGTH) {
              groupedLines[lastIndex] = {
                ...groupedLines[lastIndex],
                text: combined,
              }
            } else {
              // н•©м№ҳл©ҙ л„Ҳл¬ҙ кёёл©ҙ лі„лҸ„лЎң м¶”к°Җ
              groupedLines.push({
                id: groupedLines.length + 1,
                text: trimmedUnit,
              })
            }
          } else {
            // мІ« лІҲм§ё к·ёлЈ№мқҙл©ҙ к·ёлҢҖлЎң м¶”к°Җ
            groupedLines.push({
              id: groupedLines.length + 1,
              text: trimmedUnit,
            })
          }
        }
        // мқҳлҜё лӢЁмң„к°Җ л„Ҳл¬ҙ кёёл©ҙ л¬ёмһҘ лӢЁмң„лЎң лӮҳлҲ„кё°
        else {
          // л¬ёмһҘ л¶ҖнҳёлЎң лӮҳлҲ„кё°
          const sentences = trimmedUnit.split(/([.!?гҖӮпјҒпјҹ]\s*)/).filter(s => s.trim().length > 0)
          let currentGroup = ""
          
          for (let i = 0; i < sentences.length; i++) {
            const sentence = sentences[i].trim()
            if (!sentence) continue
            
            const potentialLength = currentGroup ? (currentGroup + " " + sentence).length : sentence.length
            
            if (potentialLength > MAX_LINE_LENGTH && currentGroup) {
              groupedLines.push({
                id: groupedLines.length + 1,
                text: currentGroup,
              })
              currentGroup = sentence
            } else if (potentialLength >= TARGET_LINE_LENGTH && potentialLength <= MAX_LINE_LENGTH) {
              const finalText = currentGroup ? currentGroup + " " + sentence : sentence
              groupedLines.push({
                id: groupedLines.length + 1,
                text: finalText,
              })
              currentGroup = ""
            } else {
              currentGroup = currentGroup ? currentGroup + " " + sentence : sentence
            }
          }
          
          if (currentGroup) {
            if (groupedLines.length > 0 && currentGroup.length < MIN_LINE_LENGTH) {
              const lastIndex = groupedLines.length - 1
              groupedLines[lastIndex] = {
                ...groupedLines[lastIndex],
                text: groupedLines[lastIndex].text + " " + currentGroup,
              }
            } else {
              groupedLines.push({
                id: groupedLines.length + 1,
                text: currentGroup,
              })
            }
          }
        }
      }
      
      return groupedLines.map((l, index) => {
        let text = l.text.trim()
        if (text.length > 0 && !/[.!?гҖӮпјҒпјҹ]$/.test(text)) {
          text = text + "."
        }
        return { ...l, id: index + 1, text }
      })
    }

    // кё°ліё лҢҖліёмқҳ кІҪмҡ°: кё°мЎҙ лЎңм§Ғ мӮ¬мҡ© (л¬ёмһҘ л¶Җнҳё кё°мӨҖ + кёёмқҙ кё°л°ҳ к·ёлЈ№нҷ”)
    // л¬ёмһҘ л¶ҖнҳёлҘј ліҙмЎҙн•ҳл©ҙм„ң л¬ёмһҘ лӢЁмң„лЎң лӮҳлҲ„кё°
    const sentences: string[] = []
    const sentenceEndRegex = /([.!?гҖӮпјҒпјҹ])\s*/g
    let lastIndex = 0
    let match
    
    while ((match = sentenceEndRegex.exec(scriptText)) !== null) {
      const sentence = scriptText.substring(lastIndex, match.index + match[0].length).trim()
      if (sentence.length > 0) {
        sentences.push(sentence)
      }
      lastIndex = sentenceEndRegex.lastIndex
    }
    
    // л§Ҳм§Җл§ү л¶Җл¶„ мІҳлҰ¬
    if (lastIndex < scriptText.length) {
      const lastSentence = scriptText.substring(lastIndex).trim()
      if (lastSentence.length > 0) {
        sentences.push(lastSentence)
      }
    }

    if (sentences.length === 0) {
      return []
    }

    const groupedLines: Array<{ id: number; text: string }> = []
    // TTS мҶҚлҸ„: л¶„лӢ№ м•Ҫ 200-250мһҗ кё°мӨҖ
    // 10мҙҲ = м•Ҫ 33~42мһҗ, 15мҙҲ = м•Ҫ 50~63мһҗ
    const TARGET_LINE_LENGTH = 60 // лӘ©н‘ң кёёмқҙ (10~15мҙҲ л¶„лҹү, м•Ҫ 50~60мһҗ)
    const MIN_LINE_LENGTH = 35 // мөңмҶҢ кёёмқҙ (м•Ҫ 10мҙҲ л¶„лҹү)
    const MAX_LINE_LENGTH = 90 // мөңлҢҖ кёёмқҙ (м•Ҫ 15мҙҲ л¶„лҹү)
    
    let currentGroup: string[] = []
    let currentLength = 0
    
    for (let i = 0; i < sentences.length; i++) {
      const sentence = sentences[i]
      const sentenceLength = sentence.length
      const potentialLength = currentLength + (currentLength > 0 ? 1 : 0) + sentenceLength // кіөл°ұ нҸ¬н•Ё
      
      // нҳ„мһ¬ к·ёлЈ№мқҙ л№„м–ҙмһҲмңјл©ҙ м¶”к°Җ
      if (currentGroup.length === 0) {
        currentGroup.push(sentence)
        currentLength = sentenceLength
        // н•ң л¬ёмһҘмқҙ мқҙлҜё мөңлҢҖ кёёмқҙлҘј л„ҳмңјл©ҙ л°”лЎң м ҖмһҘ
        if (sentenceLength > MAX_LINE_LENGTH) {
          groupedLines.push({
            id: groupedLines.length + 1,
            text: sentence,
          })
          currentGroup = []
          currentLength = 0
        }
        continue
      }
      
      // нҳ„мһ¬ к·ёлЈ№м—җ м¶”к°Җн–Ҳмқ„ л•Ң мөңлҢҖ кёёмқҙлҘј л„ҳмңјл©ҙ нҳ„мһ¬ к·ёлЈ№ м ҖмһҘн•ҳкі  мғҲлЎң мӢңмһ‘
      if (potentialLength > MAX_LINE_LENGTH) {
        if (currentGroup.length > 0) {
          const groupText = currentGroup.join(" ")
          groupedLines.push({
            id: groupedLines.length + 1,
            text: groupText,
          })
        }
        currentGroup = [sentence]
        currentLength = sentenceLength
        // н•ң л¬ёмһҘмқҙ мқҙлҜё мөңлҢҖ кёёмқҙлҘј л„ҳмңјл©ҙ л°”лЎң м ҖмһҘ
        if (sentenceLength > MAX_LINE_LENGTH) {
          groupedLines.push({
            id: groupedLines.length + 1,
            text: sentence,
          })
          currentGroup = []
          currentLength = 0
        }
        continue
      }
      
      // лӘ©н‘ң кёёмқҙм—җ лҸ„лӢ¬н•ҳл©ҙ (лӘ©н‘ң кёёмқҙ мқҙмғҒмқҙкі  мөңлҢҖ кёёмқҙ лҜёл§Ң) к·ёлЈ№ м ҖмһҘ
      if (potentialLength >= TARGET_LINE_LENGTH && potentialLength <= MAX_LINE_LENGTH) {
        currentGroup.push(sentence)
        const groupText = currentGroup.join(" ")
        groupedLines.push({
          id: groupedLines.length + 1,
          text: groupText,
        })
        currentGroup = []
        currentLength = 0
        continue
      }
      
      // лӘ©н‘ң кёёмқҙліҙлӢӨ мһ‘мңјл©ҙ кі„мҶҚ м¶”к°Җ
      if (potentialLength < TARGET_LINE_LENGTH) {
        currentGroup.push(sentence)
        currentLength = potentialLength
        continue
      }
    }
    
    // лӮЁмқҖ л¬ёмһҘл“Ө мІҳлҰ¬
    if (currentGroup.length > 0) {
      const remainingText = currentGroup.join(" ")
      // мөңмҶҢ кёёмқҙлҘј л§ҢмЎұн•ҳкұ°лӮҳ л§Ҳм§Җл§ү к·ёлЈ№мқҙл©ҙ м ҖмһҘ
      if (remainingText.length >= MIN_LINE_LENGTH || groupedLines.length === 0) {
        groupedLines.push({
          id: groupedLines.length + 1,
          text: remainingText,
        })
      } else if (groupedLines.length > 0) {
        // мөңмҶҢ кёёмқҙ лҜёл§Ңмқҙл©ҙ л§Ҳм§Җл§ү к·ёлЈ№м—җ н•©м№ҳкё°
        const lastIndex = groupedLines.length - 1
        groupedLines[lastIndex] = {
          ...groupedLines[lastIndex],
          text: groupedLines[lastIndex].text + " " + remainingText,
        }
      }
    }
    
    // ID мһ¬м •л ¬ л°Ҹ л§Ҳм№Ён‘ң м¶”к°Җ
    return groupedLines.map((l, index) => {
      let text = l.text.trim()
      // л¬ёмһҘ лҒқм—җ л§Ҳм№Ён‘ңк°Җ м—Ҷмңјл©ҙ м¶”к°Җ
      if (text.length > 0 && !/[.!?гҖӮпјҒпјҹ]$/.test(text)) {
        text = text + "."
      }
      return { ...l, id: index + 1, text }
    })
  }

  const handleBasicScriptGeneration = async () => {
    if (!scriptPlan) {
      alert("лҢҖліё кё°нҡҚм•Ҳмқ„ лЁјм Җ мғқм„ұн•ҙмЈјм„ёмҡ”.")
      return
    }

    setIsGenerating(true)
    try {
      console.log("[v0] кё°ліё лҢҖліё мғқм„ұ мӢңмһ‘")
      const topic = isCustomTopicSelected ? customTopic : selectedTopic
      // м„ нғқн•ң мӢңк°„м—җ л§һм¶° лҢҖліё кёёмқҙ кі„мӮ° (1мҙҲлӢ№ 6.9мһҗ - лӘ©н‘ң кёҖмһҗмҲҳ кі„мӮ°)
      const targetChars = Math.floor(scriptDuration * 60 * 6.9)
      // folktale м№ҙн…Ңкі лҰ¬ лҳҗлҠ” Type D м„ нғқ мӢң мһҗлҸҷмңјлЎң мҠӨнҶ лҰ¬ лӘЁл“ңлЎң м„Өм •
      const shouldUseStoryMode = isStoryMode || selectedCategory === "folktale" || selectedContentType === "D"
      const fullScript = await generateFinalScript(scriptPlan, topic || "", getApiKey(), scriptDuration, targetChars, selectedCategory, shouldUseStoryMode)
      
      // лҢҖліё л§Ҳм§Җл§үм—җ CTA м¶”к°Җ
      const ctaText = "\n\nмқҙ мҳҒмғҒмқҙ лҸ„мӣҖмқҙ лҗҳм…ЁлӢӨл©ҙ мўӢм•„мҡ”мҷҖ кө¬лҸ… л¶ҖнғҒл“ңлҰҪлӢҲлӢӨ. м—¬лҹ¬л¶„мқҳ мқ‘мӣҗмқҙ м ңкІҢ нҒ° нһҳмқҙ лҗ©лӢҲлӢӨ. лӢӨмқҢ мҳҒмғҒм—җм„ңлҸ„ лҚ” мң мҡ©н•ң м •ліҙлҘј кіөмң н•ҳкІ мҠөлӢҲлӢӨ. к°җмӮ¬н•©лӢҲлӢӨ."
      const scriptWithCTA = fullScript.trim() + ctaText
      
      setScript(scriptWithCTA)
      
      // лҢҖліёмқ„ л¬ёмһҘ лӢЁмң„лЎң л¶„лҰ¬н•ҳкі  м Ғм Ҳн•ң кёёмқҙлЎң л¬¶кё°
      const groupedLines = splitScriptIntoLines(fullScript)
      
      setScriptLines(groupedLines)
      setCompletedSteps((prev) => [...prev, "script"])
      console.log("[v0] кё°ліё лҢҖліё мғқм„ұ мҷ„лЈҢ, л¬ёмһҘ к·ёлЈ№ мҲҳ:", groupedLines.length)
    } catch (error) {
      console.error("кё°ліё лҢҖліё мғқм„ұ мӢӨнҢЁ:", error)
      const errorMessage = error instanceof Error ? error.message : "м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ."
      alert(`кё°ліё лҢҖліё мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ: ${errorMessage}`)
    } finally {
      setIsGenerating(false)
    }
  }

  const handleRefinedScriptGeneration = async () => {
    if (!scriptPlan) {
      alert("лҢҖліё кё°нҡҚм•Ҳмқ„ лЁјм Җ мғқм„ұн•ҙмЈјм„ёмҡ”.")
      return
    }

    setIsGenerating(true)
    const startTime = Date.now()
    
    // folktale м№ҙн…Ңкі лҰ¬ лҳҗлҠ” Type D м„ нғқ мӢң мһҗлҸҷмңјлЎң мҠӨнҶ лҰ¬ лӘЁл“ңлЎң м„Өм •
    const shouldUseStoryMode = isStoryMode || selectedCategory === "folktale" || selectedContentType === "D"
    
    // лӘ©н‘ң кёҖмһҗмҲҳ кё°л°ҳ мҳҲмғҒ мӢңк°„ кі„мӮ° (1000мһҗлӢ№ м•Ҫ 10-15мҙҲ мҶҢмҡ” к°Җм •)
    const topic = isCustomTopicSelected ? customTopic : selectedTopic
    // лӘ©н‘ң кёҖмһҗмҲҳ кі„мӮ°: кё°ліё кі„мӮ° + м—¬мң л¶„ 500мһҗ (AIк°Җ лҚ” л§Һмқҙ мһ‘м„ұн•ҳлҸ„лЎқ мң лҸ„)
    const baseTargetChars = Math.floor(scriptDuration * 60 * 6.9) // 1мҙҲлӢ№ 6.9мһҗ
    const targetChars = baseTargetChars + 500 // м—¬мң л¶„ 500мһҗ м¶”к°Җ
    const estimatedSeconds = Math.max(30, Math.ceil(targetChars / 1000 * 12)) // мөңмҶҢ 30мҙҲ, 1000мһҗлӢ№ 12мҙҲ
    const estimatedTime = estimatedSeconds * 1000 // л°ҖлҰ¬мҙҲлЎң ліҖнҷҳ
    
    // м§„н–үлҘ  м—…лҚ°мқҙнҠё мқён„°лІҢ мӢңмһ‘ (л¶„н• мқҙ м—ҶлҠ” кІҪмҡ°м—җл§Ң мӢңк°„ кё°л°ҳ м§„н–үлҘ  н‘ңмӢң)
    const progressInterval = setInterval(() => {
      const elapsedTime = Date.now() - startTime
      // л¶„н• мқҙ м—ҶлҠ” кІҪмҡ°м—җл§Ң мӢңк°„ кё°л°ҳ м§„н–үлҘ  кі„мӮ°
      const shouldSplit = scriptDuration && scriptDuration >= 10
      if (!shouldSplit) {
        // л¶„н• мқҙ м—ҶлҠ” кІҪмҡ°: мӢңк°„ кё°л°ҳ м§„н–үлҘ 
      const progress = Math.min(95, Math.floor((elapsedTime / estimatedTime) * 100))
      setScriptGenerationProgress({
        progress,
        elapsedTime: Math.floor(elapsedTime / 1000), // мҙҲ лӢЁмң„
        estimatedTime: Math.floor(estimatedTime / 1000) // мҙҲ лӢЁмң„
      })
      }
      // л¶„н• мқҙ мһҲлҠ” кІҪмҡ°лҠ” л¶„н• лі„лЎң м§„н–үлҘ мқҙ м—…лҚ°мқҙнҠёлҗҳлҜҖлЎң мқён„°лІҢм—җм„ңлҠ” м—…лҚ°мқҙнҠён•ҳм§Җ м•ҠмқҢ
    }, 500) // 0.5мҙҲл§ҲлӢӨ м—…лҚ°мқҙнҠё
    
    try {
      console.log("[v0] м •көҗн•ң лҢҖліё мғқм„ұ мӢңмһ‘")
      const geminiApiKey = getGeminiApiKey()
      if (!geminiApiKey) {
        clearInterval(progressInterval)
        setScriptGenerationProgress(null)
        alert("Gemini API нӮӨлҘј м„Өм •н•ҙмЈјм„ёмҡ”. м„Өм • нҺҳмқҙм§Җм—җм„ң API нӮӨлҘј мһ…л Ҙн•ҳкі  м ҖмһҘн•ҙмЈјм„ёмҡ”.")
        return
      }
      // folktale м№ҙн…Ңкі лҰ¬ лҳҗлҠ” Type D м„ нғқ мӢң мһҗлҸҷмңјлЎң мҠӨнҶ лҰ¬ лӘЁл“ңлЎң м„Өм •
      const shouldUseStoryMode = isStoryMode || selectedCategory === "folktale" || selectedContentType === "D"
      
      // л¶„н•  мҲҳ кі„мӮ° (10л¶„ мқҙмғҒмқј л•Ңл§Ң л¶„н• )
      const shouldSplit = scriptDuration && scriptDuration >= 10
      let totalParts = 1
      if (scriptDuration === 10) totalParts = 2
      else if (scriptDuration === 15) totalParts = 3
      else if (scriptDuration === 20) totalParts = 4
      else if (scriptDuration === 25) totalParts = 5
      else if (scriptDuration === 30) totalParts = 6
      else if (scriptDuration === 35) totalParts = 7
      else if (scriptDuration === 40) totalParts = 8

      let fullScript = ""

      if (!shouldSplit) {
        // 5л¶„: н•ң лІҲм—җ мғқм„ұ
        const response = await fetch("/api/generate-refined-script", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
        scriptPlan, 
            topic: topic || "",
            duration: scriptDuration,
        targetChars, 
            isStoryMode: shouldUseStoryMode,
            apiKey: geminiApiKey
          })
        })

        if (!response.ok) {
          let errorData
          try {
            errorData = await response.json()
          } catch (e) {
            if (response.status === 504 || response.status === 408) {
              throw new Error("лҢҖліё мғқм„ұ мӢңк°„мқҙ л„Ҳл¬ҙ мҳӨлһҳ кұёлҰҪлӢҲлӢӨ. Vercelмқҳ нғҖмһ„м•„мӣғ м ңн•ң(5л¶„)мқ„ мҙҲкіјн–ҲмҠөлӢҲлӢӨ.")
            }
            throw new Error(`лҢҖліё мғқм„ұ мӢӨнҢЁ: ${response.status}`)
          }
          throw new Error(errorData.error || `лҢҖліё мғқм„ұ мӢӨнҢЁ: ${response.status}`)
        }

        const result = await response.json()
        if (!result || !result.script) {
          throw new Error("лҢҖліё мғқм„ұ мқ‘лӢөмқҙ мҳ¬л°”лҘҙм§Җ м•ҠмҠөлӢҲлӢӨ.")
        }
        fullScript = result.script
      } else {
        // 10л¶„ мқҙмғҒ: к°Ғ л¶„н• мқ„ мҲңм°Ём ҒмңјлЎң нҳём¶ң
        const parts: string[] = []
        
        for (let partNumber = 1; partNumber <= totalParts; partNumber++) {
          // м§„н–үлҘ  м—…лҚ°мқҙнҠё (л¶„н•  кё°л°ҳ)
          const progress = Math.floor(((partNumber - 1) / totalParts) * 100)
          setScriptGenerationProgress({
            progress,
            elapsedTime: Math.floor((Date.now() - startTime) / 1000),
            estimatedTime: Math.floor(estimatedTime / 1000),
            currentPart: partNumber,
            totalParts
          })

          console.log(`[v0] ${partNumber}/${totalParts} л¶„н•  мғқм„ұ мӢңмһ‘`)
          
          // нғҖмһ„м•„мӣғ мӢң мһҗлҸҷ мһ¬мӢңлҸ„ лЎңм§Ғ
          const maxRetries = 3
          let partScript: string | null = null
          let lastError: Error | null = null
          
          for (let retryAttempt = 0; retryAttempt < maxRetries; retryAttempt++) {
            try {
              if (retryAttempt > 0) {
                const retryDelay = 2000 * retryAttempt // 2мҙҲ, 4мҙҲ, 6мҙҲ
                console.log(`[v0] ${partNumber}нҡҢм°Ё мһ¬мӢңлҸ„ ${retryAttempt}/${maxRetries - 1} - ${retryDelay}ms нӣ„ мһ¬мӢңлҸ„...`)
                await new Promise((resolve) => setTimeout(resolve, retryDelay))
              }
              
              const response = await fetch("/api/generate-refined-script-part", {
                method: "POST",
                headers: {
                  "Content-Type": "application/json",
                },
                body: JSON.stringify({
                  scriptPlan,
                  topic: topic || "",
                  duration: scriptDuration,
                  partNumber,
                  totalParts,
                  targetChars,
                  previousParts: parts.join("\n\n"),
                  isStoryMode: shouldUseStoryMode,
                  apiKey: geminiApiKey
                })
              })

              if (!response.ok) {
                let errorData
                try {
                  errorData = await response.json()
                } catch (e) {
                  // JSON нҢҢмӢұ мӢӨнҢЁ мӢң (нғҖмһ„м•„мӣғ л“ұ)
                  if (response.status === 504 || response.status === 408) {
                    if (retryAttempt < maxRetries - 1) {
                      console.warn(`[v0] ${partNumber}нҡҢм°Ё нғҖмһ„м•„мӣғ л°ңмғқ, мһ¬мӢңлҸ„ мӨ‘... (${retryAttempt + 1}/${maxRetries})`)
                      lastError = new Error(`нғҖмһ„м•„мӣғ (мһ¬мӢңлҸ„ ${retryAttempt + 1}/${maxRetries})`)
                      continue
                    }
                    throw new Error(`${partNumber}нҡҢм°Ё мғқм„ұ мӢңк°„мқҙ л„Ҳл¬ҙ мҳӨлһҳ кұёлҰҪлӢҲлӢӨ. нғҖмһ„м•„мӣғмқҙ л°ңмғқн–ҲмҠөлӢҲлӢӨ.`)
                  }
                  throw new Error(`${partNumber}нҡҢм°Ё мғқм„ұ мӢӨнҢЁ: ${response.status}`)
                }
                
                // нғҖмһ„м•„мӣғ мҳӨлҘҳмқё кІҪмҡ° мһ¬мӢңлҸ„
                if (response.status === 504 || response.status === 408) {
                  if (retryAttempt < maxRetries - 1) {
                    console.warn(`[v0] ${partNumber}нҡҢм°Ё нғҖмһ„м•„мӣғ л°ңмғқ, мһ¬мӢңлҸ„ мӨ‘... (${retryAttempt + 1}/${maxRetries})`)
                    lastError = new Error(`нғҖмһ„м•„мӣғ: ${errorData.error || 'м„ңлІ„ мқ‘лӢө мӢңк°„ мҙҲкіј'} (мһ¬мӢңлҸ„ ${retryAttempt + 1}/${maxRetries})`)
                    continue
                  }
                  throw new Error(`${partNumber}нҡҢм°Ё мғқм„ұ мӢңк°„мқҙ л„Ҳл¬ҙ мҳӨлһҳ кұёлҰҪлӢҲлӢӨ. нғҖмһ„м•„мӣғмқҙ л°ңмғқн–ҲмҠөлӢҲлӢӨ.`)
                }
                
                // лӢӨлҘё мҳӨлҘҳлҠ” мһ¬мӢңлҸ„н•ҳм§Җ м•Ҡкі  л°”лЎң throw
                throw new Error(errorData.error || `${partNumber}нҡҢм°Ё мғқм„ұ мӢӨнҢЁ: ${response.status}`)
              }

              const result = await response.json()
              if (!result || !result.script) {
                if (retryAttempt < maxRetries - 1) {
                  console.warn(`[v0] ${partNumber}нҡҢм°Ё мқ‘лӢөмқҙ мҳ¬л°”лҘҙм§Җ м•ҠмқҢ, мһ¬мӢңлҸ„ мӨ‘... (${retryAttempt + 1}/${maxRetries})`)
                  lastError = new Error(`${partNumber}нҡҢм°Ё мғқм„ұ мқ‘лӢөмқҙ мҳ¬л°”лҘҙм§Җ м•ҠмҠөлӢҲлӢӨ.`)
                  continue
                }
                throw new Error(`${partNumber}нҡҢм°Ё мғқм„ұ мқ‘лӢөмқҙ мҳ¬л°”лҘҙм§Җ м•ҠмҠөлӢҲлӢӨ.`)
              }

              // м„ұкіө
              partScript = result.script
              console.log(`[v0] ${partNumber}/${totalParts} л¶„н•  мғқм„ұ мҷ„лЈҢ: ${result.script.length}мһҗ`)
              break // м„ұкіө мӢң лЈЁн”„ нғҲм¶ң
              
            } catch (error) {
              lastError = error instanceof Error ? error : new Error(String(error))
              
              // нғҖмһ„м•„мӣғ кҙҖл Ё мҳӨлҘҳк°Җ м•„лӢҲл©ҙ мһ¬мӢңлҸ„н•ҳм§Җ м•ҠмқҢ
              const errorMessage = lastError.message
              if (!errorMessage.includes("нғҖмһ„м•„мӣғ") && !errorMessage.includes("504") && !errorMessage.includes("408") && !errorMessage.includes("timeout")) {
                throw lastError
              }
              
              // нғҖмһ„м•„мӣғ мҳӨлҘҳмқҙкі  мһ¬мӢңлҸ„ к°ҖлҠҘн•ң кІҪмҡ°
              if (retryAttempt < maxRetries - 1) {
                console.warn(`[v0] ${partNumber}нҡҢм°Ё мҳӨлҘҳ л°ңмғқ, мһ¬мӢңлҸ„ мӨ‘... (${retryAttempt + 1}/${maxRetries}):`, errorMessage)
                continue
              }
              
              // лӘЁл“  мһ¬мӢңлҸ„ мӢӨнҢЁ
              throw lastError
            }
          }
          
          // мһ¬мӢңлҸ„ нӣ„м—җлҸ„ мӢӨнҢЁн•ң кІҪмҡ°
          if (!partScript) {
            throw lastError || new Error(`${partNumber}нҡҢм°Ё мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.`)
          }
          
          parts.push(partScript)
          
          // л¶„н•  мҷ„лЈҢ нӣ„ м§„н–үлҘ  м—…лҚ°мқҙнҠё
          const completedProgress = Math.floor((partNumber / totalParts) * 100)
          setScriptGenerationProgress({
            progress: completedProgress,
            elapsedTime: Math.floor((Date.now() - startTime) / 1000),
            estimatedTime: Math.floor(estimatedTime / 1000),
            currentPart: partNumber,
            totalParts
          })
        }

        // лӘЁл“  л¶„н•  н•©м№ҳкё°
        fullScript = parts.join("\n\n")
        
        // мөңмў… м§„н–үлҘ  100%лЎң м—…лҚ°мқҙнҠё
        setScriptGenerationProgress({
          progress: 100,
          elapsedTime: Math.floor((Date.now() - startTime) / 1000),
          estimatedTime: Math.floor(estimatedTime / 1000),
          currentPart: totalParts,
          totalParts
        })
      }
      
      // лҢҖліёмқҙ л№„м–ҙмһҲлҠ”м§Җ нҷ•мқё
      if (!fullScript || typeof fullScript !== 'string' || fullScript.trim().length === 0) {
        throw new Error("мғқм„ұлҗң лҢҖліёмқҙ л№„м–ҙмһҲмҠөлӢҲлӢӨ. лӢӨмӢң мӢңлҸ„н•ҙмЈјм„ёмҡ”.")
      }
      
      // лҢҖліё л§Ҳм§Җл§үм—җ CTA м¶”к°Җ (мқҙлҜё CTAк°Җ мһҲмңјл©ҙ м¶”к°Җн•ҳм§Җ м•ҠмқҢ)
      const ctaText = "\n\nмқҙ мҳҒмғҒмқҙ лҸ„мӣҖмқҙ лҗҳм…ЁлӢӨл©ҙ мўӢм•„мҡ”мҷҖ кө¬лҸ… л¶ҖнғҒл“ңлҰҪлӢҲлӢӨ. м—¬лҹ¬л¶„мқҳ мқ‘мӣҗмқҙ м ңкІҢ нҒ° нһҳмқҙ лҗ©лӢҲлӢӨ. лӢӨмқҢ мҳҒмғҒм—җм„ңлҸ„ лҚ” мң мҡ©н•ң м •ліҙлҘј кіөмң н•ҳкІ мҠөлӢҲлӢӨ. к°җмӮ¬н•©лӢҲлӢӨ."
      // CTA мӨ‘ліө мІҙнҒ¬: лҢҖліё лҒқл¶Җл¶„м—җ мқҙлҜё CTAк°Җ мһҲлҠ”м§Җ нҷ•мқё
      const scriptEnd = fullScript.trim().slice(-200) // л§Ҳм§Җл§ү 200мһҗл§Ң нҷ•мқё
      const hasCTA = scriptEnd.includes("мўӢм•„мҡ”мҷҖ кө¬лҸ…") || (scriptEnd.includes("мўӢм•„мҡ”") && scriptEnd.includes("кө¬лҸ…")) || scriptEnd.includes("кө¬лҸ… л¶ҖнғҒл“ңлҰҪлӢҲлӢӨ")
      const scriptWithCTA = hasCTA ? fullScript : fullScript.trim() + ctaText
      
      setScript(scriptWithCTA)
      
      // м •көҗн•ң лҢҖліёмқҖ мқҳлҜё/мһҘл©ҙ кё°л°ҳмңјлЎң лӮҳлҲ„кё°
      const groupedLines = splitScriptIntoLines(scriptWithCTA, true)
      
      setScriptLines(groupedLines)
      setCompletedSteps((prev) => [...prev, "script"])
      console.log("[v0] м •көҗн•ң лҢҖліё мғқм„ұ мҷ„лЈҢ, л¬ёмһҘ к·ёлЈ№ мҲҳ:", groupedLines.length)
      playNotificationSound() // м•ҢлҰјмқҢ мһ¬мғқ
      
      // мҷ„лЈҢ мӢң 100% н‘ңмӢң
      setScriptGenerationProgress({
        progress: 100,
        elapsedTime: Math.floor((Date.now() - startTime) / 1000),
        estimatedTime: Math.floor(estimatedTime / 1000)
      })
    } catch (error) {
      console.error("м •көҗн•ң лҢҖліё мғқм„ұ мӢӨнҢЁ:", error)
      
      // мҳӨлҘҳ л©”мӢңм§Җ м¶”м¶ң л°Ҹ к°ңм„ 
      let errorMessage = "м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ."
      
      if (error instanceof Error) {
        errorMessage = error.message
        
        // Next.js Server Components мҳӨлҘҳмқё кІҪмҡ° лҚ” м№ңм Ҳн•ң л©”мӢңм§Җ м ңкіө
        if (errorMessage.includes("Server Components render") || errorMessage.includes("digest")) {
          errorMessage = "м„ңлІ„м—җм„ң лҢҖліё мғқм„ұ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ. к°ҖлҠҘн•ң мӣҗмқё:\n\n" +
            "1. Gemini API нҳём¶ң мӢӨнҢЁ (API нӮӨ нҷ•мқё н•„мҡ”)\n" +
            "2. л„ӨнҠёмӣҢнҒ¬ м—°кІ° л¬ём ң\n" +
            "3. м„ңлІ„ нғҖмһ„м•„мӣғ (мғқм„ұ мӢңк°„мқҙ л„Ҳл¬ҙ кёём–ҙм§җ)\n" +
            "4. л©”лӘЁлҰ¬ л¶ҖмЎұ\n\n" +
            "к°ңл°ңмһҗ лҸ„кө¬ мҪҳмҶ”м—җм„ң мһҗм„ён•ң мҳӨлҘҳ м •ліҙлҘј нҷ•мқён•ҳм„ёмҡ”."
        }
        
        // кө¬мІҙм Ғмқё мҳӨлҘҳ л©”мӢңм§Җк°Җ мһҲлҠ” кІҪмҡ° к·ёлҢҖлЎң мӮ¬мҡ©
        if (errorMessage.includes("API нӮӨ") || errorMessage.includes("SAFETY") || errorMessage.includes("RECITATION")) {
          // мқҙлҜё кө¬мІҙм Ғмқё л©”мӢңм§Җк°Җ мһҲмқҢ
        }
      }
      
      // мҳӨлҘҳ мғҒм„ё м •ліҙлҘј мҪҳмҶ”м—җ м¶ңл Ҙ (л””лІ„к№…мҡ©)
      if (error instanceof Error && error.stack) {
        console.error("мҳӨлҘҳ мҠӨнғқ нҠёл ҲмқҙмҠӨ:", error.stack)
      }
      
      alert(`м •көҗн•ң лҢҖліё мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ: ${errorMessage}\n\nн•ңлІҲлҚ” мғқм„ұн•ҙмЈјм„ёмҡ”.`)
    } finally {
      clearInterval(progressInterval)
      setIsGenerating(false)
      // мҷ„лЈҢ нӣ„ 1мҙҲ л’Ө м§„н–үлҘ  мҙҲкё°нҷ”
      setTimeout(() => {
        setScriptGenerationProgress(null)
      }, 1000)
    }
  }

  const handleDirectScriptSubmit = () => {
    if (!directScript.trim()) return

    setScript(directScript)
    
    // лҢҖліёмқ„ л¬ёмһҘ лӢЁмң„лЎң л¶„лҰ¬н•ҳкі  м Ғм Ҳн•ң кёёмқҙлЎң л¬¶кё°
    const groupedLines = splitScriptIntoLines(directScript)
    
    setScriptLines(groupedLines)
    setCompletedSteps((prev) => [...prev, "script"])
    setShowDirectScriptInput(false)
    console.log("[v0] м§Ғм ‘ мһ…л Ҙлҗң лҢҖліё м Ғмҡ© мҷ„лЈҢ, л¬ёмһҘ к·ёлЈ№ мҲҳ:", groupedLines.length)
  }

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text)
  }

  // м»ӨмҠӨн…Җ мқҙлҜём§Җ мғқм„ұ (н•ңкёҖ н”„лЎ¬н”„нҠё мһ…л Ҙ)
  const handleGenerateCustomImage = async (lineId: number) => {
    if (!customImagePrompt.trim()) {
      alert("мқҙлҜём§Җ м„ӨлӘ…мқ„ мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
      return
    }

    const openaiApiKey = getApiKey("openai_api_key")
    const replicateApiKey = getApiKey("replicate_api_key")

    if (!openaiApiKey) {
      alert("OpenAI API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
      return
    }

    if (!replicateApiKey) {
      alert("Replicate API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
      return
    }

    setIsGeneratingCustomImage(true)
    
    // мқҙлҜём§Җ мғқм„ұ мӢңмһ‘ мӢң н•ҙлӢ№ мқҙлҜём§Җмқҳ мҳҒмғҒ лҚ°мқҙн„° мҙҲкё°нҷ”
    setConvertedVideos((prev) => {
      const newMap = new Map(prev)
      newMap.delete(lineId)
      return newMap
    })
    
    try {
      // н•ңкёҖ н”„лЎ¬н”„нҠёлҘј мҳҒм–ҙлЎң ліҖнҷҳ
      console.log(`[v0] м»ӨмҠӨн…Җ мқҙлҜём§Җ мғқм„ұ мӢңмһ‘ (мӨ„ ${lineId}):`, customImagePrompt)
      
      // generateCustomPrompt н•ЁмҲҳ мӮ¬мҡ©
      const { generateCustomPrompt } = await import("./actions")
      let englishPrompt = await generateCustomPrompt(customImagePrompt, openaiApiKey)
      
      // м№ҙн…Ңкі лҰ¬лі„ н”„лЎ¬н”„нҠё м¶”к°Җ (16:9 л№„мңЁ к°•м ң)
      // лӘЁл“  м№ҙн…Ңкі лҰ¬м—җм„ң мҠӨнғҖмқј м Ғмҡ©
      if (imageStyle) {
        englishPrompt = await generateImagePrompt(customImagePrompt, openaiApiKey, selectedCategory || "health", imageStyle)
      } else {
        // лӢӨлҘё м№ҙн…Ңкі лҰ¬лҠ” кё°ліё н”„лЎ¬н”„нҠём—җ 16:9 к°•м ң м¶”к°Җ
        if (!englishPrompt.toLowerCase().includes("16:9") && !englishPrompt.toLowerCase().includes("aspect ratio")) {
          englishPrompt = `${englishPrompt}, 16:9 aspect ratio, cinematic composition`
        }
      }
      
      console.log(`[v0] ліҖнҷҳлҗң мҳҒм–ҙ н”„лЎ¬н”„нҠё:`, englishPrompt)

      // мқҙлҜём§Җ мғқм„ұ
      const response = await fetch("/api/generate-image", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          scriptText: customImagePrompt,
          openaiApiKey,
          replicateApiKey,
          category: selectedCategory || "health",
          historyStyle: imageStyle,
          customPrompt: englishPrompt, // м§Ғм ‘ н”„лЎ¬н”„нҠё м „лӢ¬
        }),
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "мқҙлҜём§Җ мғқм„ұ мӢӨнҢЁ")
      }

      const data = await response.json()
      console.log(`[v0] м»ӨмҠӨн…Җ мқҙлҜём§Җ мғқм„ұ мҷ„лЈҢ:`, data.imageUrl)

      // мғқм„ұлҗң мқҙлҜём§Җ м—…лҚ°мқҙнҠё
      setGeneratedImages((prev) => {
        const filtered = prev.filter((img) => img.lineId !== lineId)
        return [
          ...filtered,
          {
            lineId: lineId,
            imageUrl: data.imageUrl,
            prompt: englishPrompt,
            createdAt: Date.now(), // мқҙлҜём§Җ мғқм„ұ мӢңк°„ м ҖмһҘ
          },
        ]
      })

      setCustomImageDialogOpen(null)
      setCustomImagePrompt("")
      // alert("мқҙлҜём§Җк°Җ мғқм„ұлҗҳм—ҲмҠөлӢҲлӢӨ!") // мҷ„лЈҢ м•ҢлҰј м ңкұ°
    } catch (error) {
      console.error(`[v0] м»ӨмҠӨн…Җ мқҙлҜём§Җ мғқм„ұ мӢӨнҢЁ (мӨ„ ${lineId}):`, error)
      alert(`мқҙлҜём§Җ мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ: ${error instanceof Error ? error.message : "м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳ"}`)
    } finally {
      setIsGeneratingCustomImage(false)
    }
  }

  // мқҙлҜём§Җ/мҳҒмғҒ м—…лЎңл“ң н•ёл“Өлҹ¬
  const handleImageUpload = async (lineId: number, file: File) => {
    try {
      // лҸҷмҳҒмғҒ нҢҢмқј м°ЁлӢЁ
      if (file.type.startsWith("video/")) {
        alert("лҸҷмҳҒмғҒ нҢҢмқјмқҖ м—…лЎңл“ңн•  мҲҳ м—ҶмҠөлӢҲлӢӨ. мқҙлҜём§Җ нҢҢмқјл§Ң м—…лЎңл“ң к°ҖлҠҘн•©лӢҲлӢӨ.")
        return
      }
      
      // мқҙлҜём§Җ нҢҢмқјл§Ң мІҳлҰ¬
      // 16:9 л№„мңЁлЎң мқҙлҜём§Җ лҰ¬мӮ¬мқҙмҰҲ
      const resizedImage = await resizeImageTo16_9(file)
      
      // Base64лЎң ліҖнҷҳ
      const reader = new FileReader()
      reader.onloadend = () => {
        const base64 = reader.result as string
        const imageUrl = base64

        // м—…лЎңл“ңлҗң мқҙлҜём§Җ м—…лҚ°мқҙнҠё
        setGeneratedImages((prev) => {
          const filtered = prev.filter((img) => img.lineId !== lineId)
          return [
            ...filtered,
            {
              lineId: lineId,
              imageUrl: imageUrl,
              prompt: "мӮ¬мҡ©мһҗ м—…лЎңл“ң мқҙлҜём§Җ",
            },
          ]
        })
        
        // мқҙлҜём§ҖлЎң көҗмІҙн–ҲмңјлҜҖлЎң ліҖнҷҳлҗң мҳҒмғҒ м ңкұ°
        setConvertedVideos((prev) => {
          const newMap = new Map(prev)
          newMap.delete(lineId)
          return newMap
        })

        // мқҙлҜём§Җ ліҖкІҪ мӢң videoData мҙҲкё°нҷ” (лҜёлҰ¬ліҙкё° мһ¬мғқм„ұ н•„мҡ”)
        setVideoData(null)
        setAutoImages([])
        
        // alert("мқҙлҜём§Җк°Җ м—…лЎңл“ңлҗҳм—ҲмҠөлӢҲлӢӨ!") // мҷ„лЈҢ м•ҢлҰј м ңкұ°
      }
      reader.readAsDataURL(resizedImage)
    } catch (error) {
      console.error(`[v0] нҢҢмқј м—…лЎңл“ң мӢӨнҢЁ (мӨ„ ${lineId}):`, error)
      alert(`нҢҢмқј м—…лЎңл“ңм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ: ${error instanceof Error ? error.message : "м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳ"}`)
    }
  }

  // Scene мқҙлҜём§Җ м—…лЎңл“ң н•ёл“Өлҹ¬ (лҸҷмҳҒмғҒ м—…лЎңл“ң л¶Ҳк°Җ)
  const handleSceneImageUpload = async (sceneNumber: number, imageNumber: number, file: File) => {
    try {
      // лҸҷмҳҒмғҒ нҢҢмқј м°ЁлӢЁ
      if (file.type.startsWith("video/")) {
        alert("лҸҷмҳҒмғҒ нҢҢмқјмқҖ м—…лЎңл“ңн•  мҲҳ м—ҶмҠөлӢҲлӢӨ. мқҙлҜём§Җ нҢҢмқјл§Ң м—…лЎңл“ң к°ҖлҠҘн•©лӢҲлӢӨ.")
        return
      }
      
      // мқҙлҜём§Җ нҢҢмқјл§Ң мІҳлҰ¬
      // 16:9 л№„мңЁлЎң мқҙлҜём§Җ лҰ¬мӮ¬мқҙмҰҲ
      const resizedImage = await resizeImageTo16_9(file)
      
      // Base64лЎң ліҖнҷҳ
      const reader = new FileReader()
      reader.onloadend = () => {
        const base64 = reader.result as string
        const imageUrl = base64

        // м—…лЎңл“ңлҗң мқҙлҜём§Җ м—…лҚ°мқҙнҠё
        setSceneImagePrompts((prev) => {
          return prev.map((scene) => {
            if (scene.sceneNumber === sceneNumber) {
              return {
                ...scene,
                images: scene.images.map((img) => {
                  if (img.imageNumber === imageNumber) {
                    return {
                      ...img,
                      imageUrl: imageUrl,
                    }
                  }
                  return img
                }),
              }
            }
            return scene
          })
        })
        
        // мқҙлҜём§ҖлЎң көҗмІҙн–ҲмңјлҜҖлЎң ліҖнҷҳлҗң мҳҒмғҒ м ңкұ°
        setConvertedSceneVideos((prev) => {
          const newMap = new Map(prev)
          newMap.delete(`${sceneNumber}-${imageNumber}`)
          return newMap
        })

        // мқҙлҜём§Җ ліҖкІҪ мӢң videoData мҙҲкё°нҷ” (лҜёлҰ¬ліҙкё° мһ¬мғқм„ұ н•„мҡ”)
        setVideoData(null)
        setAutoImages([])
        
        // alert("мқҙлҜём§Җк°Җ м—…лЎңл“ңлҗҳм—ҲмҠөлӢҲлӢӨ!") // мҷ„лЈҢ м•ҢлҰј м ңкұ°
      }
      reader.readAsDataURL(resizedImage)
    } catch (error) {
      console.error(`[Scene] нҢҢмқј м—…лЎңл“ң мӢӨнҢЁ (Scene ${sceneNumber}, Image ${imageNumber}):`, error)
      alert(`нҢҢмқј м—…лЎңл“ңм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ: ${error instanceof Error ? error.message : "м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳ"}`)
    }
  }

  // мқҙлҜём§ҖлҘј 16:9 л№„мңЁлЎң лҰ¬мӮ¬мқҙмҰҲн•ҳлҠ” н•ЁмҲҳ
  const resizeImageTo16_9 = (file: File): Promise<File> => {
    return new Promise((resolve, reject) => {
      const img = new Image()
      img.onload = () => {
        const canvas = document.createElement("canvas")
        const ctx = canvas.getContext("2d")
        if (!ctx) {
          reject(new Error("Canvas contextлҘј к°Җм ёмҳ¬ мҲҳ м—ҶмҠөлӢҲлӢӨ."))
          return
        }

        // 16:9 л№„мңЁ кі„мӮ°
        const targetAspect = 16 / 9
        const imgAspect = img.width / img.height

        let drawWidth = img.width
        let drawHeight = img.height
        let x = 0
        let y = 0

        if (imgAspect > targetAspect) {
          // мқҙлҜём§Җк°Җ лҚ” л„“мқҢ - лҶ’мқҙ кё°мӨҖмңјлЎң нҒ¬лЎӯ
          drawHeight = img.height
          drawWidth = img.height * targetAspect
          x = (img.width - drawWidth) / 2
        } else {
          // мқҙлҜём§Җк°Җ лҚ” лҶ’мқҢ - л„Ҳл№„ кё°мӨҖмңјлЎң нҒ¬лЎӯ
          drawWidth = img.width
          drawHeight = img.width / targetAspect
          y = (img.height - drawHeight) / 2
        }

        canvas.width = 1920 // кі н•ҙмғҒлҸ„
        canvas.height = 1080

        ctx.drawImage(img, x, y, drawWidth, drawHeight, 0, 0, canvas.width, canvas.height)

        canvas.toBlob((blob) => {
          if (!blob) {
            reject(new Error("мқҙлҜём§Җ ліҖнҷҳм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ."))
            return
          }
          const resizedFile = new File([blob], file.name, { type: "image/jpeg" })
          resolve(resizedFile)
        }, "image/jpeg", 0.9)
      }
      img.onerror = () => reject(new Error("мқҙлҜём§Җ лЎңл“ңм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ."))
      img.src = URL.createObjectURL(file)
    })
  }

  // Scene мқҙлҜём§ҖлҘј мҳҒмғҒмңјлЎң ліҖнҷҳн•ҳлҠ” н•ёл“Өлҹ¬
  const handleConvertSceneImageToVideo = async (sceneNumber: number, imageNumber: number, imageUrl: string) => {
    const videoKey = `${sceneNumber}-${imageNumber}`
    
    if (isConvertingSceneVideo.has(videoKey)) {
      return
    }

    setIsConvertingSceneVideo((prev) => new Set(prev).add(videoKey))
    
    const replicateApiKey = typeof window !== "undefined" ? localStorage.getItem("replicate_api_key") || undefined : undefined

    if (!replicateApiKey) {
      alert("Replicate API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
      setIsConvertingSceneVideo((prev) => {
        const newSet = new Set(prev)
        newSet.delete(videoKey)
        return newSet
      })
      return
    }

    try {
      const { convertImageToVideo } = await import("./actions")
      const videoUrl = await convertImageToVideo(imageUrl, replicateApiKey)
      
      if (videoUrl) {
        setConvertedSceneVideos((prev) => {
          const newMap = new Map(prev)
          newMap.set(videoKey, videoUrl)
          return newMap
        })
        console.log(`[Scene Video] мқҙлҜём§Җ-нҲ¬-л№„л””мҳӨ ліҖнҷҳ мҷ„лЈҢ (Scene ${sceneNumber}, Image ${imageNumber}):`, videoUrl)
      }
    } catch (error) {
      console.error(`[Scene Video] мқҙлҜём§Җ-нҲ¬-л№„л””мҳӨ ліҖнҷҳ мӢӨнҢЁ (Scene ${sceneNumber}, Image ${imageNumber}):`, error)
      alert(`мҳҒмғҒ ліҖнҷҳм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ: ${error instanceof Error ? error.message : "м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳ"}`)
    } finally {
      setIsConvertingSceneVideo((prev) => {
        const newSet = new Set(prev)
        newSet.delete(videoKey)
        return newSet
      })
    }
  }

  // м„ нғқн•ң мқҙлҜём§ҖлҘј мҳҒмғҒмңјлЎң ліҖнҷҳн•ҳлҠ” н•ёл“Өлҹ¬
  const handleConvertImagesToVideo = async () => {
    if (selectedImagesForVideo.size === 0) {
      alert("мҳҒмғҒмңјлЎң ліҖнҷҳн•  мқҙлҜём§ҖлҘј м„ нғқн•ҙмЈјм„ёмҡ”.")
      return
    }

    setIsConvertingToVideo(true)
    // лЎңм»¬мҠӨнҶ лҰ¬м§Җм—җм„ң м§Ғм ‘ к°Җм ёмҳӨкё° (лӢӨлҘё л¶Җл¶„кіј лҸҷмқјн•ң л°©мӢқ)
    const replicateApiKey = typeof window !== "undefined" ? localStorage.getItem("replicate_api_key") || undefined : undefined

    if (!replicateApiKey) {
      alert("Replicate API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
      setIsConvertingToVideo(false)
      return
    }

    try {
      const selectedImageIds = Array.from(selectedImagesForVideo)
      let successCount = 0

      for (const imageId of selectedImageIds) {
        const image = generatedImages.find((img) => img.lineId === imageId)
        if (!image) continue

        try {
          console.log(`[Video] мқҙлҜём§Җ-нҲ¬-л№„л””мҳӨ ліҖнҷҳ мӢңмһ‘ (л¬ёмһҘ ${imageId}):`, image.imageUrl)
          
          // м„ңлІ„ м•Ўм…ҳ нҳём¶ң
          const { convertImageToVideo } = await import("./actions")
          const videoUrl = await convertImageToVideo(image.imageUrl, replicateApiKey)
          
          if (videoUrl) {
            setConvertedVideos((prev) => {
              const newMap = new Map(prev)
              newMap.set(imageId, videoUrl)
              return newMap
            })
            successCount++
            console.log(`[Video] мқҙлҜём§Җ-нҲ¬-л№„л””мҳӨ ліҖнҷҳ мҷ„лЈҢ (л¬ёмһҘ ${imageId}):`, videoUrl)
          }
        } catch (error) {
          console.error(`[Video] мқҙлҜём§Җ-нҲ¬-л№„л””мҳӨ ліҖнҷҳ мӢӨнҢЁ (л¬ёмһҘ ${imageId}):`, error)
          // мӢӨнҢЁн•ҙлҸ„ кі„мҶҚ м§„н–ү
        }
      }

      if (successCount > 0) {
        alert(`${successCount}к°ңмқҳ мқҙлҜём§Җк°Җ мҳҒмғҒмңјлЎң ліҖнҷҳлҗҳм—ҲмҠөлӢҲлӢӨ!`)
        // м„ нғқ н•ҙм ң
        setSelectedImagesForVideo(new Set())
      } else {
        alert("мҳҒмғҒ ліҖнҷҳм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ. лӢӨмӢң мӢңлҸ„н•ҙмЈјм„ёмҡ”.")
      }
    } catch (error) {
      console.error("[Video] мҳҒмғҒ ліҖнҷҳ мӢӨнҢЁ:", error)
      alert("мҳҒмғҒ ліҖнҷҳ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.")
    } finally {
      setIsConvertingToVideo(false)
    }
  }

  // мғҲлЎңмҡҙ мқҙлҜём§Җ мғқм„ұ н•ёл“Өлҹ¬ (л¬ёмһҘ лҰ¬мҠӨнҠё кё°л°ҳ)
  const handleGenerateImagesForLines = async () => {
    if (scriptLines.length === 0) {
      alert("мғқм„ұлҗң л¬ёмһҘ лҰ¬мҠӨнҠёк°Җ м—ҶмҠөлӢҲлӢӨ. лЁјм Җ лҢҖліёмқ„ мғқм„ұн•ҙмЈјм„ёмҡ”.")
      return
    }

    const openaiApiKey = getApiKey("openai_api_key")
    const replicateApiKey = getApiKey("replicate_api_key")

    if (!openaiApiKey) {
      alert("OpenAI API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
      if (isAutoMode) {
        setIsAutoMode(false)
        setAutoModeStep("")
      }
      return
    }

    if (!replicateApiKey) {
      alert("Replicate API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
      if (isAutoMode) {
        setIsAutoMode(false)
        setAutoModeStep("")
      }
      return
    }

    setIsGeneratingImages(true)
    if (isAutoMode) {
      setAutoModeStep("мқҙлҜём§Җ мғқм„ұ мӨ‘...")
      setAutoModeProgress({ current: "4/7", total: 7 })
    }
    setImageGenerationProgress({ current: 0, total: scriptLines.length })
    // кё°мЎҙ мқҙлҜём§Җ мҙҲкё°нҷ”
    setGeneratedImages([])
    // ліҖнҷҳлҗң мҳҒмғҒ лҚ°мқҙн„° мҙҲкё°нҷ” (мҳҒмғҒ м ңкұ°)
    setConvertedVideos(new Map())

    let successCount = 0
    let commonStylePrompt: string | undefined = undefined

    try {
      // 1. м „мІҙ лҢҖліёмқҳ кіөнҶө мҠӨнғҖмқј н”„лЎ¬н”„нҠё мғқм„ұ (мІ« лІҲм§ё мқҙлҜём§Җ мғқм„ұ м „)
      const topic = isCustomTopicSelected ? customTopic : selectedTopic
      if (topic) {
        try {
          // commonStylePrompt = await generateCommonStylePrompt(
          //   topic,
          //   selectedCategory || "health",
          //   openaiApiKey,
          //   imageStyle
          // )
          // мһ„мӢңлЎң мЈјм„қ мІҳлҰ¬ (import м—җлҹ¬ н•ҙкІ° нӣ„ нҷңм„ұнҷ”)
          commonStylePrompt = undefined
          // console.log("[v0] кіөнҶө мҠӨнғҖмқј н”„лЎ¬н”„нҠё мғқм„ұ мҷ„лЈҢ:", commonStylePrompt)
        } catch (error) {
          console.warn("[v0] кіөнҶө мҠӨнғҖмқј н”„лЎ¬н”„нҠё мғқм„ұ мӢӨнҢЁ, кі„мҶҚ м§„н–ү:", error)
          // кіөнҶө мҠӨнғҖмқј мғқм„ұ мӢӨнҢЁн•ҙлҸ„ кі„мҶҚ м§„н–ү
        }
      }

      // 2. к°Ғ л¬ёмһҘм—җ лҢҖн•ҙ мқҙлҜём§Җ мғқм„ұ
      shouldStopImageGeneration.current = false // мӨ‘лӢЁ н”Ңлһҳк·ё мҙҲкё°нҷ”
      let characterAnchor: string | null = null // мәҗлҰӯн„° м•өм»Ө (мІ« лІҲм§ё мқҙлҜём§Җм—җм„ң м¶”м¶ң)
      let backgroundStyle: string | null = null // л°°кІҪ мҠӨнғҖмқј (мӢӨмӮ¬нҷ” мқјкҙҖм„ұ мң м§Җмҡ©)
      let renderingStyle: string | null = null // к·ёлҰјмІҙ/л ҢлҚ”л§Ғ мҠӨнғҖмқј (мӢӨмӮ¬нҷ” мқјкҙҖм„ұ мң м§Җмҡ©)
      const isRealistic = imageStyle === "realistic" || imageStyle === "realistic2"
      
      for (let i = 0; i < scriptLines.length; i++) {
        // мӨ‘лӢЁ мІҙнҒ¬
        if (shouldStopImageGeneration.current) {
          console.log("[v0] мқҙлҜём§Җ мғқм„ұ мӨ‘лӢЁлҗЁ")
          // alert(`мқҙлҜём§Җ мғқм„ұмқ„ мӨ‘лӢЁн–ҲмҠөлӢҲлӢӨ. (${successCount}к°ң мғқм„ұ мҷ„лЈҢ)`) // мҷ„лЈҢ м•ҢлҰј м ңкұ°
          break
        }
        
        const line = scriptLines[i]
        setImageGenerationProgress({ current: i + 1, total: scriptLines.length })

        try {
          // API routeлҘј нҶөн•ҙ мқҙлҜём§Җ мғқм„ұ
          console.log(`[v0] мқҙлҜём§Җ мғқм„ұ мӨ‘... (${i + 1}/${scriptLines.length})`)
          const response = await fetch("/api/generate-image", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              scriptText: line.text,
              openaiApiKey,
              replicateApiKey,
              category: selectedCategory || "health",
              historyStyle: imageStyle, // лӘЁл“  м№ҙн…Ңкі лҰ¬м—җм„ң мҠӨнғҖмқј м Ғмҡ©
              commonStylePrompt, // кіөнҶө мҠӨнғҖмқј н”„лЎ¬н”„нҠё м „лӢ¬
              topic: isCustomTopicSelected ? customTopic : selectedTopic, // мЈјм ң м „лӢ¬ (мӢңлҢҖм Ғ л°°кІҪ нҢҢм•…мҡ©)
              characterAnchor: characterAnchor || undefined, // мәҗлҰӯн„° м•өм»Ө м „лӢ¬ (мІ« лІҲм§ё мқҙлҜём§Җ мқҙнӣ„)
              backgroundStyle: backgroundStyle || undefined, // л°°кІҪ мҠӨнғҖмқј м „лӢ¬ (мӢӨмӮ¬нҷ” мқјкҙҖм„ұ мң м§Җмҡ©)
              renderingStyle: renderingStyle || undefined, // к·ёлҰјмІҙ мҠӨнғҖмқј м „лӢ¬ (мӢӨмӮ¬нҷ” мқјкҙҖм„ұ мң м§Җмҡ©)
            }),
          })

          if (!response.ok) {
            const errorData = await response.json()
            throw new Error(errorData.error || "мқҙлҜём§Җ мғқм„ұ мӢӨнҢЁ")
          }

          const data = await response.json()
          console.log(`[v0] мқҙлҜём§Җ мғқм„ұ мҷ„лЈҢ:`, data.imageUrl)

          // мІ« лІҲм§ё мқҙлҜём§Җм—җм„ң мәҗлҰӯн„° м•өм»Ө, л°°кІҪ мҠӨнғҖмқј, к·ёлҰјмІҙ м¶”м¶ң
          if (i === 0 && data.imageUrl) {
            try {
              const { extractCharacterAnchor, extractBackgroundAndRenderingStyle } = await import("./actions")
              const topic = isCustomTopicSelected ? customTopic : selectedTopic
              
              // мәҗлҰӯн„° м•өм»Ө м¶”м¶ң (мқёл¬јмқҙ мһҲлҠ” кІҪмҡ°)
              if (!characterAnchor) {
                const extractedAnchor = await extractCharacterAnchor(
                  data.imageUrl,
                  line.text,
                  openaiApiKey,
                  topic || undefined
                )
                if (extractedAnchor) {
                  characterAnchor = extractedAnchor
                  console.log("[v0] мәҗлҰӯн„° м•өм»Ө м¶”м¶ң мҷ„лЈҢ:", characterAnchor.substring(0, 100) + "...")
                } else {
                  console.log("[v0] мәҗлҰӯн„° м•өм»Ө м¶”м¶ң: мқёл¬ј м—ҶмқҢ лҳҗлҠ” м¶”м¶ң мӢӨнҢЁ")
                }
              }
              
              // мӢӨмӮ¬нҷ” мҠӨнғҖмқјмқј л•Ң л°°кІҪ мҠӨнғҖмқјкіј к·ёлҰјмІҙ м¶”м¶ң
              if (isRealistic) {
                const { backgroundStyle: extractedBg, renderingStyle: extractedRendering } = await extractBackgroundAndRenderingStyle(
                  data.imageUrl,
                  openaiApiKey
                )
                if (extractedBg) {
                  backgroundStyle = extractedBg
                  console.log("[v0] л°°кІҪ мҠӨнғҖмқј м¶”м¶ң мҷ„лЈҢ:", backgroundStyle.substring(0, 100) + "...")
                }
                if (extractedRendering) {
                  renderingStyle = extractedRendering
                  console.log("[v0] к·ёлҰјмІҙ мҠӨнғҖмқј м¶”м¶ң мҷ„лЈҢ:", renderingStyle.substring(0, 100) + "...")
                }
              } else {
                // м• лӢҲл©”мқҙм…ҳ мҠӨнғҖмқј(мң лҹҪн’Қ к·ёлһҳн”Ҫ л…ёлё” нҸ¬н•Ё)м—җм„ңлҸ„ к·ёлҰјмІҙ мҠӨнғҖмқј м¶”м¶ң (мқјкҙҖм„ұ мң м§Җ)
                const isAnimation = imageStyle === "stickman-animation" || imageStyle === "animation2" || imageStyle === "animation3" || imageStyle === "semi-realistic-animation"
                if (isAnimation) {
                  try {
                    const { renderingStyle: extractedRendering } = await extractBackgroundAndRenderingStyle(
                      data.imageUrl,
                      openaiApiKey
                    )
                    if (extractedRendering) {
                      renderingStyle = extractedRendering
                      console.log("[v0] м• лӢҲл©”мқҙм…ҳ к·ёлҰјмІҙ мҠӨнғҖмқј м¶”м¶ң мҷ„лЈҢ:", renderingStyle.substring(0, 100) + "...")
                    }
                  } catch (error) {
                    console.warn("[v0] м• лӢҲл©”мқҙм…ҳ к·ёлҰјмІҙ мҠӨнғҖмқј м¶”м¶ң мӢӨнҢЁ:", error)
                  }
                }
              }
            } catch (error) {
              console.warn("[v0] мҠӨнғҖмқј м •ліҙ м¶”м¶ң мӢӨнҢЁ, кі„мҶҚ м§„н–ү:", error)
            }
          }

          // мқҙлҜём§Җк°Җ мғқм„ұлҗҳл©ҙ мҰүмӢң state м—…лҚ°мқҙнҠё (мӢӨмӢңк°„ н‘ңмӢң)
          setGeneratedImages((prev) => [
            ...prev,
            {
              lineId: line.id,
              imageUrl: data.imageUrl,
              prompt: data.prompt,
              createdAt: Date.now(), // мқҙлҜём§Җ мғқм„ұ мӢңк°„ м ҖмһҘ
            },
          ])
          successCount++
        } catch (error) {
          console.error(`[v0] мқҙлҜём§Җ мғқм„ұ мӢӨнҢЁ (мӨ„ ${line.id}):`, error)
          // мӢӨнҢЁн•ҙлҸ„ кі„мҶҚ м§„н–ү
        }
      }

      console.log("[v0] лӘЁл“  мқҙлҜём§Җ мғқм„ұ мҷ„лЈҢ, м„ұкіө:", successCount, "к°ң")
      if (successCount > 0) playNotificationSound() // м•ҢлҰјмқҢ мһ¬мғқ
      
      // мқҙлҜём§Җк°Җ н•ҳлӮҳлқјлҸ„ мғқм„ұлҗҳм—Ҳмңјл©ҙ мҷ„лЈҢ н‘ңмӢң
      if (successCount > 0) {
        setCompletedSteps((prev) => {
          if (!prev.includes("image")) return [...prev, "image"]
          return prev
        })
        if (!isAutoMode) {
          // alert(`${successCount}к°ңмқҳ мқҙлҜём§Җк°Җ мғқм„ұлҗҳм—ҲмҠөлӢҲлӢӨ!`) // мҷ„лЈҢ м•ҢлҰј м ңкұ°
        }
        
        // мһҗлҸҷнҷ” лӘЁл“ңмқј л•Ң лӢӨмқҢ лӢЁкі„ мһҗлҸҷ м§„н–ү (TTS мғқм„ұ)
        if (isAutoMode) {
          console.log("[v0] мһҗлҸҷнҷ” лӘЁл“ң: TTS мғқм„ұ мӢңмһ‘")
          setTimeout(() => handleGenerateTTSForLines(), 2000)
        }
      } else {
        alert("мқҙлҜём§Җ мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ. лӢӨмӢң мӢңлҸ„н•ҙмЈјм„ёмҡ”.")
        if (isAutoMode) {
          setIsAutoMode(false)
          setAutoModeStep("")
        }
      }
    } catch (error) {
      console.error("мқҙлҜём§Җ мғқм„ұ мӢӨнҢЁ:", error)
      alert("мқҙлҜём§Җ мғқм„ұ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.")
      if (isAutoMode) {
        setIsAutoMode(false)
        setAutoModeStep("")
      }
    } finally {
      setIsGeneratingImages(false)
      setImageGenerationProgress({ current: 0, total: 0 })
      shouldStopImageGeneration.current = false // мӨ‘лӢЁ н”Ңлһҳк·ё мҙҲкё°нҷ”
    }
  }


  // мҲҳнҚјнҶӨ мқҢм„ұ лӘ©лЎқ к°Җм ёмҳӨкё°
  const fetchSupertoneVoices = async () => {
    setIsLoadingSupertoneVoices(true)
    try {
      const supertoneApiKey = getApiKey("supertone_api_key")
      if (!supertoneApiKey) {
        alert("мҲҳнҚјнҶӨ API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
        setIsLoadingSupertoneVoices(false)
        return
      }

      const response = await fetch(`/api/supertone-voices?apiKey=${encodeURIComponent(supertoneApiKey)}`, {
        method: "GET",
        headers: {
          "Content-Type": "application/json",
        },
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "мқҢм„ұ лӘ©лЎқмқ„ к°Җм ёмҳӨлҠ”лҚ° мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.")
      }

      const data = await response.json()
      if (data.success && data.voices) {
        // нҠ№м • мқҢм„ұ м ңмҷё: "лӢ¬нҢҪмқҙA", "кё°м–өмқҳм •л №_м•Ңл§Ҳлғҗ", "нӢҲмғҲмқҳм •л №_м•Ңл§Ҳлғҗ"
        const excludedNames = ["лӢ¬нҢҪмқҙA", "кё°м–өмқҳм •л №_м•Ңл§Ҳлғҗ", "нӢҲмғҲмқҳм •л №_м•Ңл§Ҳлғҗ"]
        const filteredVoices = data.voices.filter((voice: { name: string }) => 
          !excludedNames.some(excluded => voice.name.includes(excluded))
        )
        setSupertoneVoices(filteredVoices)
        // мІ« лІҲм§ё мқҢм„ұмқ„ кё°ліё м„ нғқ
        if (filteredVoices.length > 0 && !selectedSupertoneVoiceId) {
          setSelectedSupertoneVoiceId(filteredVoices[0].voice_id)
          setSelectedVoiceId(`supertone-${filteredVoices[0].voice_id}`)
        }
      } else {
        throw new Error(data.error || "мқҢм„ұ лӘ©лЎқмқ„ к°Җм ёмҳӨлҠ”лҚ° мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.")
      }
    } catch (error) {
      console.error("мҲҳнҚјнҶӨ мқҢм„ұ лӘ©лЎқ к°Җм ёмҳӨкё° мӢӨнҢЁ:", error)
      alert(`мҲҳнҚјнҶӨ мқҢм„ұ лӘ©лЎқмқ„ к°Җм ёмҳӨлҠ”лҚ° мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ: ${error instanceof Error ? error.message : "м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳ"}`)
    } finally {
      setIsLoadingSupertoneVoices(false)
    }
  }

  // м–ём–ҙ мҪ”л“ңлҘј н•ңкөӯм–ҙлЎң ліҖнҷҳн•ҳлҠ” н•ЁмҲҳ
  const languageCodeToKorean = (code: string): string => {
    const languageMap: Record<string, string> = {
      "ar": "м•„лһҚм–ҙ",
      "bg": "л¶Ҳк°ҖлҰ¬м•„м–ҙ",
      "cs": "мІҙмҪ”м–ҙ",
      "da": "лҚҙл§ҲнҒ¬м–ҙ",
      "de": "лҸ…мқјм–ҙ",
      "el": "к·ёлҰ¬мҠӨм–ҙ",
      "en": "мҳҒм–ҙ",
      "es": "мҠӨнҺҳмқём–ҙ",
      "et": "м—җмҠӨнҶ лӢҲм•„м–ҙ",
      "fi": "н•ҖлһҖл“ңм–ҙ",
      "fr": "н”„лһ‘мҠӨм–ҙ",
      "hi": "нһҢл””м–ҙ",
      "hu": "н—қк°ҖлҰ¬м–ҙ",
      "id": "мқёлҸ„л„ӨмӢңм•„м–ҙ",
      "it": "мқҙнғҲлҰ¬м•„м–ҙ",
      "ja": "мқјліём–ҙ",
      "ko": "н•ңкөӯм–ҙ",
      "nl": "л„ӨлҚңлһҖл“ңм–ҙ",
      "pl": "нҸҙлһҖл“ңм–ҙ",
      "pt": "нҸ¬лҘҙнҲ¬к°Ҳм–ҙ",
      "ro": "лЈЁл§ҲлӢҲм•„м–ҙ",
      "ru": "лҹ¬мӢңм•„м–ҙ",
      "vi": "лІ нҠёлӮЁм–ҙ",
    }
    return languageMap[code.toLowerCase()] || code
  }

  // лӘ©мҶҢлҰ¬ лҜёлҰ¬л“Јкё° н•ЁмҲҳ
  const handlePreviewVoice = async (voiceId: string) => {
    setPreviewingVoiceId(voiceId)
    
    try {
      let response: Response
      
      // мҲҳнҚјнҶӨмқё кІҪмҡ°
      if (voiceId?.startsWith("supertone-")) {
        const actualVoiceId = voiceId.replace("supertone-", "")
        const supertoneApiKey = getApiKey("supertone_api_key")
        
        if (!supertoneApiKey) {
          alert("мҲҳнҚјнҶӨ API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
          setPreviewingVoiceId(null)
          return
        }
        
        response = await fetch("/api/supertone-tts", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            text: "м—¬лҹ¬л¶„ нҷҳмҳҒн•©лӢҲлӢӨ",
            voiceId: actualVoiceId,
            apiKey: supertoneApiKey,
            style: selectedSupertoneStyle || "neutral", // мӮ¬мҡ©мһҗк°Җ м„ нғқн•ң мҠӨнғҖмқј
            language: "ko", // кё°ліёк°’: н•ңкөӯм–ҙ
          }),
        })
      } else if (voiceId?.startsWith("ttsmaker-")) {
        // TTSMakerмқё кІҪмҡ°
        const voiceName = voiceId.replace("ttsmaker-", "")
        // лӮЁм„ұ5лҠ” мқҢлҶ’мқҙ -10% (pitch 0.9)
        const pitch = voiceName === "лӮЁм„ұ5" ? 0.9 : 1.0
        const ttsmakerApiKey = getApiKey("ttsmaker_api_key")
        
        if (!ttsmakerApiKey) {
          alert("TTSMaker API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
          setPreviewingVoiceId(null)
          return
        }
        
        console.log(`[лҜёлҰ¬л“Јкё°] TTSMaker voice: ${voiceId} -> ${voiceName}, pitch: ${pitch}`)
        response = await fetch("/api/ttsmaker", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            text: "м—¬лҹ¬л¶„ нҷҳмҳҒн•©лӢҲлӢӨ",
            voice: voiceName,
            speed: 1.0,
            pitch: pitch,
            apiKey: ttsmakerApiKey,
          }),
        })
      } else if (voiceId?.startsWith("elevenlabs-")) {
        // ElevenLabsмқё кІҪмҡ° (мғҲлЎңмҡҙ нҳ•мӢқ: elevenlabs-{voiceId})
        const actualVoiceId = voiceId.replace("elevenlabs-", "")
        let elevenlabsApiKey = typeof window !== "undefined" 
          ? (localStorage.getItem("elevenlabs_api_key") || "").trim() 
          : null
        
        // localStorageм—җ м—Ҷмңјл©ҙ getApiKeyлЎң мӢңлҸ„
        if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
          const apiKey = getApiKey("elevenlabs")
          elevenlabsApiKey = apiKey !== undefined ? apiKey : null
        }
        
        if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
          alert("ElevenLabs API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
          setPreviewingVoiceId(null)
          return
        }
        
        response = await fetch("/api/elevenlabs-tts", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            text: "м—¬лҹ¬л¶„ нҷҳмҳҒн•©лӢҲлӢӨ",
            voiceId: actualVoiceId,
            apiKey: elevenlabsApiKey,
          }),
        })
      } else {
        // кё°ліё ElevenLabs мІҳлҰ¬ (н•ҳмң„ нҳёнҷҳм„ұ: voiceIdк°Җ м§Ғм ‘ ElevenLabs voice IDмқё кІҪмҡ°)
        let elevenlabsApiKey = typeof window !== "undefined" 
          ? (localStorage.getItem("elevenlabs_api_key") || "").trim() 
          : null
        
        // localStorageм—җ м—Ҷмңјл©ҙ getApiKeyлЎң мӢңлҸ„
        if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
          const apiKey = getApiKey("elevenlabs")
          elevenlabsApiKey = apiKey !== undefined ? apiKey : null
        }
        
        if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
          alert("ElevenLabs API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
          setPreviewingVoiceId(null)
          return
        }
        
        response = await fetch("/api/elevenlabs-tts", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            text: "м—¬лҹ¬л¶„ нҷҳмҳҒн•©лӢҲлӢӨ",
            voiceId: voiceId,
            apiKey: elevenlabsApiKey,
          }),
        })
      }

      if (!response.ok) {
        let errorMessage = "лҜёлҰ¬л“Јкё° мӢӨнҢЁ"
        try {
          // responseлҘј cloneн•ҙм„ң мқҪкё° (мӣҗліё responseлҠ” лӮҳмӨ‘м—җ мӮ¬мҡ©н•  мҲҳ мһҲлҸ„лЎқ)
          const clonedResponse = response.clone()
          const errorData = await clonedResponse.json()
          errorMessage = errorData.error || errorData.message || `HTTP ${response.status}: ${response.statusText}`
          
          // 404 мҳӨлҘҳмқё кІҪмҡ° лҚ” лӘ…нҷ•н•ң л©”мӢңм§Җ
          if (response.status === 404 && errorMessage.includes("not found")) {
            errorMessage = `м»ӨмҠӨн…Җ лӘ©мҶҢлҰ¬лҘј м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ.\n\n${errorMessage}\n\nк°ҖлҠҘн•ң мӣҗмқё:\n1. лӘ©мҶҢлҰ¬ IDк°Җ мҳ¬л°”лҘҙм§Җ м•ҠмҠөлӢҲлӢӨ\n2. API нӮӨк°Җ н•ҙлӢ№ лӘ©мҶҢлҰ¬лҘј мғқм„ұн•ң кі„м •мқҳ нӮӨк°Җ м•„лӢҷлӢҲлӢӨ\n3. лӘ©мҶҢлҰ¬к°Җ мӮӯм ңлҗҳм—Ҳкұ°лӮҳ л№„кіөк°ң мғҒнғңмһ…лӢҲлӢӨ\n\nн•ҙкІ° л°©лІ•:\n1. лӘ©мҶҢлҰ¬ IDлҘј лӢӨмӢң нҷ•мқён•ҳм„ёмҡ”\n2. лӘ©мҶҢлҰ¬лҘј мғқм„ұн•ң кі„м •мқҳ API нӮӨлҘј мӮ¬мҡ©н•ҳм„ёмҡ”\n3. ElevenLabs лҢҖмӢңліҙл“ңм—җм„ң лӘ©мҶҢлҰ¬к°Җ мЎҙмһ¬н•ҳлҠ”м§Җ нҷ•мқён•ҳм„ёмҡ”`
          }
        } catch (e) {
          // JSON нҢҢмӢұ мӢӨнҢЁ мӢң н…ҚмҠӨнҠёлЎң мқҪкё° мӢңлҸ„
          try {
            const errorText = await response.text()
            errorMessage = errorText || `HTTP ${response.status}: ${response.statusText}`
          } catch (textError) {
            errorMessage = `HTTP ${response.status}: ${response.statusText}`
          }
        }
        throw new Error(errorMessage)
      }

      const data = await response.json()
      
      if (data.audioUrl) {
        setPreviewAudioUrl(data.audioUrl)
        // мҳӨл””мҳӨ мһ¬мғқ
        const audio = new Audio(data.audioUrl)
        audio.play()
        audio.onended = () => {
          setPreviewingVoiceId(null)
          setPreviewAudioUrl(null)
        }
        audio.onerror = () => {
          setPreviewingVoiceId(null)
          setPreviewAudioUrl(null)
        }
      } else if (data.audioBase64) {
        // Base64лҘј Blob URLлЎң ліҖнҷҳ
        const binaryString = atob(data.audioBase64)
        const bytes = new Uint8Array(binaryString.length)
        for (let i = 0; i < binaryString.length; i++) {
          bytes[i] = binaryString.charCodeAt(i)
        }
        const blob = new Blob([bytes], { type: "audio/mpeg" })
        const audioUrl = URL.createObjectURL(blob)
        setPreviewAudioUrl(audioUrl)
        
        const audio = new Audio(audioUrl)
        audio.play()
        audio.onended = () => {
          URL.revokeObjectURL(audioUrl)
          setPreviewingVoiceId(null)
          setPreviewAudioUrl(null)
        }
        audio.onerror = () => {
          URL.revokeObjectURL(audioUrl)
          setPreviewingVoiceId(null)
          setPreviewAudioUrl(null)
        }
      }
    } catch (error) {
      console.error("лҜёлҰ¬л“Јкё° мӢӨнҢЁ:", error)
      alert(`лҜёлҰ¬л“Јкё°м—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ: ${error instanceof Error ? error.message : "м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳ"}`)
      setPreviewingVoiceId(null)
      setPreviewAudioUrl(null)
    }
  }

  // 6.25л§Ң н•ңкёҖлЎң ліҖнҷҳн•ҳлҠ” н•ЁмҲҳ (6.25 -> мңЎмқҙмҳӨ)
  const convertNumbersToKorean = (text: string): string => {
    // 6.25л§Ң "мңЎмқҙмҳӨ"лЎң ліҖнҷҳ
    return text.replace(/6\.25/g, "мңЎмқҙмҳӨ")
  }

  // TTS мғқм„ұ мһ¬мӢңлҸ„ н—¬нҚј н•ЁмҲҳ
  const generateTTSWithRetry = async (
    line: { id: number; text: string },
    selectedVoiceId: string,
    maxRetries: number = 5,
    abortSignal?: AbortSignal
  ): Promise<{ audioUrl: string; audioBase64: string; alignment?: any }> => {
    let lastError: Error | null = null
    
    // мҲ«мһҗлҘј н•ңкёҖлЎң ліҖнҷҳ
    const convertedText = convertNumbersToKorean(line.text)
    
    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      // мӨ‘м§Җ мҡ”мІӯ нҷ•мқё
      if (abortSignal?.aborted || shouldStopTTSGeneration.current) {
        throw new Error("TTS мғқм„ұмқҙ мӨ‘м§Җлҗҳм—ҲмҠөлӢҲлӢӨ.")
      }
      
      try {
        let response: Response
        
        // TTSMakerмқё кІҪмҡ°
        if (selectedVoiceId?.startsWith("ttsmaker-")) {
          // TTSMakerмқё кІҪмҡ°
          const voiceName = selectedVoiceId.replace("ttsmaker-", "")
          const pitch = voiceName === "лӮЁм„ұ5" ? 0.9 : 1.0
          const ttsmakerApiKey = getApiKey("ttsmaker_api_key")
          
          if (!ttsmakerApiKey) {
            throw new Error("TTSMaker API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
          }
          
          response = await fetch("/api/ttsmaker", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              text: convertedText,
              voice: voiceName,
              speed: 1.0,
              pitch: pitch,
              apiKey: ttsmakerApiKey,
            }),
            signal: abortSignal, // AbortSignal м „лӢ¬
          })
        } else if (selectedVoiceId?.startsWith("supertone-")) {
          // мҲҳнҚјнҶӨмқё кІҪмҡ°
          const voiceId = selectedVoiceId.replace("supertone-", "")
          // лҜёлҰ¬л“Јкё°мҷҖ лҸҷмқјн•ң л°©мӢқмңјлЎң API нӮӨ к°Җм ёмҳӨкё°
          let supertoneApiKey = typeof window !== "undefined" 
            ? (localStorage.getItem("supertone_api_key") || "").trim() 
            : null
          
          // localStorageм—җ м—Ҷмңјл©ҙ getApiKeyлЎң мӢңлҸ„
          if (!supertoneApiKey || supertoneApiKey.length === 0) {
            const apiKey = getApiKey("supertone_api_key")
            supertoneApiKey = apiKey !== undefined ? apiKey : null
          }
          
          if (!supertoneApiKey || supertoneApiKey.length === 0) {
            throw new Error("мҲҳнҚјнҶӨ API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
          }
          
          response = await fetch("/api/supertone-tts", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              text: convertedText,
              voiceId: voiceId,
              apiKey: supertoneApiKey,
              style: selectedSupertoneStyle || "neutral", // мӮ¬мҡ©мһҗк°Җ м„ нғқн•ң мҠӨнғҖмқј
              language: "ko", // кё°ліёк°’: н•ңкөӯм–ҙ
            }),
            signal: abortSignal, // AbortSignal м „лӢ¬
          })
        } else if (selectedVoiceId?.startsWith("elevenlabs-")) {
          // ElevenLabsмқё кІҪмҡ° (мғҲлЎңмҡҙ нҳ•мӢқ: elevenlabs-{voiceId})
          const voiceId = selectedVoiceId.replace("elevenlabs-", "")
          // лҜёлҰ¬л“Јкё°мҷҖ лҸҷмқјн•ң л°©мӢқмңјлЎң API нӮӨ к°Җм ёмҳӨкё°
          let elevenlabsApiKey = getApiKey("elevenlabs_api_key") ?? null
          
          console.log(`[TTS мғқм„ұ] ElevenLabs API нӮӨ нҷ•мқё (getApiKey) - мЎҙмһ¬: ${!!elevenlabsApiKey}, кёёмқҙ: ${elevenlabsApiKey?.length || 0}`)
          
          // getApiKeyлЎң лӘ» м°ҫмңјл©ҙ localStorageм—җм„ң м§Ғм ‘ к°Җм ёмҳӨкё° (fallback)
          if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
            elevenlabsApiKey = typeof window !== "undefined" 
              ? (localStorage.getItem("elevenlabs_api_key") || "").trim() || null
              : null
            console.log(`[TTS мғқм„ұ] ElevenLabs API нӮӨ нҷ•мқё (localStorage м§Ғм ‘) - мЎҙмһ¬: ${!!elevenlabsApiKey}, кёёмқҙ: ${elevenlabsApiKey?.length || 0}`)
          }
          
          if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
            throw new Error("вқҢ ElevenLabs API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ.\n\nн•ҙкІ° л°©лІ•:\n1. м„Өм •м—җм„ң ElevenLabs API нӮӨлҘј мһ…л Ҙн•ҳм„ёмҡ”\n2. API нӮӨк°Җ мҳ¬л°”лҘём§Җ нҷ•мқён•ҳм„ёмҡ”")
          }
          
          response = await fetch("/api/elevenlabs-tts", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              text: convertedText,
              voiceId: voiceId,
              apiKey: elevenlabsApiKey,
            }),
            signal: abortSignal, // AbortSignal м „лӢ¬
          })
        } else {
          // кё°ліё ElevenLabs мІҳлҰ¬ (н•ҳмң„ нҳёнҷҳм„ұ: selectedVoiceIdк°Җ м§Ғм ‘ ElevenLabs voice IDмқё кІҪмҡ°)
          // лҜёлҰ¬л“Јкё°мҷҖ лҸҷмқјн•ң л°©мӢқмңјлЎң API нӮӨ к°Җм ёмҳӨкё°
          let elevenlabsApiKey = getApiKey("elevenlabs_api_key") ?? null
          
          console.log(`[TTS мғқм„ұ] ElevenLabs API нӮӨ нҷ•мқё (getApiKey) - мЎҙмһ¬: ${!!elevenlabsApiKey}, кёёмқҙ: ${elevenlabsApiKey?.length || 0}`)
          
          // getApiKeyлЎң лӘ» м°ҫмңјл©ҙ localStorageм—җм„ң м§Ғм ‘ к°Җм ёмҳӨкё° (fallback)
          if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
            elevenlabsApiKey = typeof window !== "undefined" 
              ? (localStorage.getItem("elevenlabs_api_key") || "").trim() || null
              : null
            console.log(`[TTS мғқм„ұ] ElevenLabs API нӮӨ нҷ•мқё (localStorage м§Ғм ‘) - мЎҙмһ¬: ${!!elevenlabsApiKey}, кёёмқҙ: ${elevenlabsApiKey?.length || 0}`)
          }
          
          if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
            throw new Error("вқҢ ElevenLabs API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ.\n\nн•ҙкІ° л°©лІ•:\n1. м„Өм •м—җм„ң ElevenLabs API нӮӨлҘј мһ…л Ҙн•ҳм„ёмҡ”\n2. API нӮӨк°Җ мҳ¬л°”лҘём§Җ нҷ•мқён•ҳм„ёмҡ”")
          }
          
          response = await fetch("/api/elevenlabs-tts", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              text: convertedText,
              voiceId: selectedVoiceId,
              apiKey: elevenlabsApiKey,
            }),
            signal: abortSignal, // AbortSignal м „лӢ¬
          })
        }

        if (!response.ok) {
          let errorMessage = "TTS мғқм„ұ мӢӨнҢЁ"
          let apiKeyName = ""
          
          // мӮ¬мҡ© мӨ‘мқё API нӮӨ мқҙлҰ„ нҷ•мқё
          if (selectedVoiceId?.startsWith("ttsmaker-")) {
            apiKeyName = "TTSMaker API нӮӨ"
          } else if (selectedVoiceId?.startsWith("supertone-")) {
            apiKeyName = "мҲҳнҚјнҶӨ(SuperTone) API нӮӨ"
          } else {
            apiKeyName = "ElevenLabs API нӮӨ"
          }
          
          try {
            const errorData = await response.json()
            const baseError = errorData.error || errorData.message || `HTTP ${response.status}: ${response.statusText}`
            
            // API нӮӨ кҙҖл Ё мҳӨлҘҳмқём§Җ нҷ•мқё
            if (response.status === 401 || response.status === 403 || 
                baseError.toLowerCase().includes("api key") || 
                baseError.toLowerCase().includes("unauthorized") ||
                baseError.toLowerCase().includes("forbidden") ||
                baseError.toLowerCase().includes("мқёмҰқ") ||
                baseError.toLowerCase().includes("нӮӨ")) {
              errorMessage = `вқҢ ${apiKeyName} мҳӨлҘҳ\n\n${baseError}\n\nн•ҙкІ° л°©лІ•:\n1. м„Өм •м—җм„ң ${apiKeyName}лҘј нҷ•мқён•ҳм„ёмҡ”\n2. API нӮӨк°Җ мҳ¬л°”лҘём§Җ нҷ•мқён•ҳм„ёмҡ”\n3. API нӮӨмқҳ мӮ¬мҡ©лҹүмқҙ мҙҲкіјлҗҳм§Җ м•Ҡм•ҳлҠ”м§Җ нҷ•мқён•ҳм„ёмҡ”`
            } else if (response.status === 429 || baseError.toLowerCase().includes("rate limit") || baseError.toLowerCase().includes("quota")) {
              errorMessage = `вқҢ ${apiKeyName} мӮ¬мҡ©лҹү мҙҲкіј\n\n${baseError}\n\nн•ҙкІ° л°©лІ•:\n1. API нӮӨмқҳ мӮ¬мҡ©лҹү н•ңлҸ„лҘј нҷ•мқён•ҳм„ёмҡ”\n2. мһ мӢң нӣ„ лӢӨмӢң мӢңлҸ„н•ҳм„ёмҡ”\n3. лӢӨлҘё API нӮӨлҘј мӮ¬мҡ©н•ҳм„ёмҡ”`
            } else {
              errorMessage = `вқҢ TTS мғқм„ұ мӢӨнҢЁ (${apiKeyName})\n\n${baseError}\n\nлёҢлқјмҡ°м Җ мҪҳмҶ”(F12)м—җм„ң мһҗм„ён•ң мҳӨлҘҳлҘј нҷ•мқён•ҙмЈјм„ёмҡ”.`
            }
          } catch (e) {
            const errorText = await response.text()
            const baseError = errorText || `HTTP ${response.status}: ${response.statusText}`
            
            if (response.status === 401 || response.status === 403) {
              errorMessage = `вқҢ ${apiKeyName} мқёмҰқ мӢӨнҢЁ\n\n${baseError}\n\nн•ҙкІ° л°©лІ•:\n1. м„Өм •м—җм„ң ${apiKeyName}лҘј нҷ•мқён•ҳм„ёмҡ”\n2. API нӮӨк°Җ мҳ¬л°”лҘём§Җ нҷ•мқён•ҳм„ёмҡ”`
            } else {
              errorMessage = `вқҢ TTS мғқм„ұ мӢӨнҢЁ (${apiKeyName})\n\n${baseError}`
            }
          }
          throw new Error(errorMessage)
        }

        const data = await response.json()
        
        if (!data.audioBase64 && !data.audioUrl) {
          throw new Error("TTS мқ‘лӢөм—җ мҳӨл””мҳӨ лҚ°мқҙн„°к°Җ м—ҶмҠөлӢҲлӢӨ.")
        }
        
        // Whisper align API нҳём¶ң м ңкұ° (STT л¶Ҳн•„мҡ”, н…ҚмҠӨнҠё кёёмқҙ л№„мңЁлЎң нғҖмқҙл°Қ кі„мӮ°)
        // ElevenLabs alignmentл§Ң мӮ¬мҡ© (мһҲлҠ” кІҪмҡ°)
        const alignment = data.alignment
        
        // м„ұкіө мӢң л°ҳнҷҳ (alignment лҚ°мқҙн„° нҸ¬н•Ё)
        return {
          audioUrl: data.audioUrl,
          audioBase64: data.audioBase64,
          alignment: alignment || undefined, // alignment лҚ°мқҙн„° нҸ¬н•Ё
        }
      } catch (error) {
        lastError = error instanceof Error ? error : new Error(String(error))
        console.warn(`[TTS мһ¬мӢңлҸ„] мӢңлҸ„ ${attempt}/${maxRetries} мӢӨнҢЁ (мӨ„ ${line.id}):`, lastError.message)
        
        // л§Ҳм§Җл§ү мӢңлҸ„к°Җ м•„лӢҲл©ҙ лҢҖкё° нӣ„ мһ¬мӢңлҸ„
        if (attempt < maxRetries) {
          const delay = Math.min(1000 * Math.pow(2, attempt - 1), 10000) // м§ҖмҲҳ л°ұмҳӨн”„, мөңлҢҖ 10мҙҲ
          console.log(`[TTS мһ¬мӢңлҸ„] ${delay}ms нӣ„ мһ¬мӢңлҸ„...`)
          await new Promise(resolve => setTimeout(resolve, delay))
        }
      }
    }
    
    // лӘЁл“  мһ¬мӢңлҸ„ мӢӨнҢЁ
    throw lastError || new Error("TTS мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.")
  }

  // к°ңлі„ л¬ёмһҘ TTS мғқм„ұ н•ёл“Өлҹ¬
  const handleGenerateTTSForSingleLine = async (lineId: number) => {
    // лЁјм Җ scriptLinesм—җм„ң м°ҫкё°
    let line = scriptLines.find((l) => l.id === lineId)
    
    // scriptLinesм—җм„ң м°ҫм§Җ лӘ»н–Ҳкі  decomposedScenesк°Җ мһҲмңјл©ҙ нҢҢмӢұн•ҙм„ң м°ҫкё°
    if (!line && decomposedScenes && decomposedScenes.trim().length > 0) {
      const sceneBlocks = decomposedScenes.split(/(?=м”¬\s+\d+)/).filter(block => block.trim().length > 0)
      let currentLineId = 1
      
      for (const sceneBlock of sceneBlocks) {
        const sceneNumMatch = sceneBlock.match(/м”¬\s+(\d+)/)
        if (!sceneNumMatch) continue
        
        const imageRegex = /\[мһҘл©ҙ\s+(\d+)\]\s*\n([\s\S]*?)(?=\[мһҘл©ҙ\s+\d+\]|м”¬\s+\d+|$)/g
        let imageMatch
        
        while ((imageMatch = imageRegex.exec(sceneBlock)) !== null) {
          const imageText = imageMatch[2].trim()
          
          if (imageText) {
            if (currentLineId === lineId) {
              // н•ҙлӢ№ lineIdм—җ л§һлҠ” н…ҚмҠӨнҠёлҘј м°ҫм•ҳмқҢ
              line = {
                id: lineId,
                text: imageText,
              }
              break
            }
            currentLineId++
          }
        }
        
        if (line) break
      }
    }
    
    if (!line) {
      alert("л¬ёмһҘмқ„ м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ.")
      return
    }

    // TTSMaker, ElevenLabs, мҲҳнҚјнҶӨмқҖ API нӮӨ н•„мҡ”
    if (selectedVoiceId?.startsWith("ttsmaker-")) {
      const ttsmakerApiKey = getApiKey("ttsmaker_api_key")
      if (!ttsmakerApiKey) {
        alert("TTSMaker API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
        return
      }
    } else if (selectedVoiceId?.startsWith("supertone-")) {
      // лҜёлҰ¬л“Јкё°мҷҖ лҸҷмқјн•ң л°©мӢқмңјлЎң API нӮӨ к°Җм ёмҳӨкё°
      let supertoneApiKey = typeof window !== "undefined" 
        ? (localStorage.getItem("supertone_api_key") || "").trim() 
        : null
      
      // localStorageм—җ м—Ҷмңјл©ҙ getApiKeyлЎң мӢңлҸ„
      if (!supertoneApiKey || supertoneApiKey.length === 0) {
        const apiKey = getApiKey("supertone_api_key")
        supertoneApiKey = apiKey !== undefined ? apiKey : null
      }
      
      if (!supertoneApiKey || supertoneApiKey.length === 0) {
        alert("мҲҳнҚјнҶӨ API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
        return
      }
    } else {
      // лҜёлҰ¬л“Јкё°мҷҖ лҸҷмқјн•ң л°©мӢқмңјлЎң API нӮӨ к°Җм ёмҳӨкё°
      let elevenlabsApiKey = typeof window !== "undefined" 
        ? (localStorage.getItem("elevenlabs_api_key") || "").trim() 
        : null
      
      // localStorageм—җ м—Ҷмңјл©ҙ getApiKeyлЎң мӢңлҸ„
      if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
        const apiKey = getApiKey("elevenlabs")
        elevenlabsApiKey = apiKey !== undefined ? apiKey : null
      }
      
      if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
        alert("ElevenLabs API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
        return
      }
    }

    // мқҙлҜё мғқм„ұлҗң TTSк°Җ мһҲлҠ”м§Җ нҷ•мқё
    const existingAudio = generatedAudios.find((audio) => audio.lineId === lineId)
    if (existingAudio) {
      const confirmReplace = confirm("мқҙлҜё мғқм„ұлҗң TTSк°Җ мһҲмҠөлӢҲлӢӨ. лӢӨмӢң мғқм„ұн•ҳмӢңкІ мҠөлӢҲк№Ң?")
      if (!confirmReplace) return
      
      // кё°мЎҙ TTS м ңкұ°
      setGeneratedAudios((prev) => prev.filter((audio) => audio.lineId !== lineId))
    }

    setGeneratingTTSForLine((prev) => new Set(prev).add(lineId))

    try {
      console.log(`[к°ңлі„ TTS] л¬ёмһҘ ${lineId} TTS мғқм„ұ мӢңмһ‘: ${line.text.substring(0, 30)}...`)
      
      // мһ¬мӢңлҸ„ лЎңм§Ғмқҙ нҸ¬н•Ёлҗң TTS мғқм„ұ
      const data = await generateTTSWithRetry(line, selectedVoiceId)
      
      console.log(`[к°ңлі„ TTS] л¬ёмһҘ ${lineId} TTS мғқм„ұ мҷ„лЈҢ`)

      // TTSк°Җ мғқм„ұлҗҳл©ҙ state м—…лҚ°мқҙнҠё
      setGeneratedAudios((prev) => {
        // кё°мЎҙ н•ӯлӘ© м ңкұ° (мһҲмңјл©ҙ)
        const filtered = prev.filter((audio) => audio.lineId !== lineId)
        return [
          ...filtered,
          {
            lineId: line.id,
            audioUrl: data.audioUrl,
            audioBase64: data.audioBase64,
          },
        ]
      })
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error)
      console.error(`[к°ңлі„ TTS] л¬ёмһҘ ${lineId} TTS мғқм„ұ мӢӨнҢЁ:`, errorMessage)
      alert(`л¬ёмһҘ ${lineId}мқҳ TTS мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ: ${errorMessage}`)
    } finally {
      setGeneratingTTSForLine((prev) => {
        const newSet = new Set(prev)
        newSet.delete(lineId)
        return newSet
      })
    }
  }

  // TTS мғқм„ұ н•ёл“Өлҹ¬ (л¬ёмһҘ лҰ¬мҠӨнҠё кё°л°ҳ)
  const handleGenerateTTSForLines = async () => {
    if (scriptLines.length === 0) {
      alert("мғқм„ұлҗң л¬ёмһҘ лҰ¬мҠӨнҠёк°Җ м—ҶмҠөлӢҲлӢӨ. лЁјм Җ лҢҖліёмқ„ мғқм„ұн•ҙмЈјм„ёмҡ”.")
      return
    }

    // TTSMaker, ElevenLabs, мҲҳнҚјнҶӨмқҖ API нӮӨ н•„мҡ”
    if (selectedVoiceId?.startsWith("supertone-")) {
      // лҜёлҰ¬л“Јкё°мҷҖ лҸҷмқјн•ң л°©мӢқмңјлЎң API нӮӨ к°Җм ёмҳӨкё°
      let supertoneApiKey = typeof window !== "undefined" 
        ? (localStorage.getItem("supertone_api_key") || "").trim() 
        : null
      
      // localStorageм—җ м—Ҷмңјл©ҙ getApiKeyлЎң мӢңлҸ„
      if (!supertoneApiKey || supertoneApiKey.length === 0) {
        const apiKey = getApiKey("supertone_api_key")
        supertoneApiKey = apiKey !== undefined ? apiKey : null
      }
      
      if (!supertoneApiKey || supertoneApiKey.length === 0) {
        alert("мҲҳнҚјнҶӨ API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
        if (isAutoMode) {
          setIsAutoMode(false)
          setAutoModeStep("")
        }
        return
      }
    } else if (!selectedVoiceId?.startsWith("ttsmaker-")) {
      // лҜёлҰ¬л“Јкё°мҷҖ лҸҷмқјн•ң л°©мӢқмңјлЎң API нӮӨ к°Җм ёмҳӨкё°
      let elevenlabsApiKey = typeof window !== "undefined" 
        ? (localStorage.getItem("elevenlabs_api_key") || "").trim() 
        : null
      
      // localStorageм—җ м—Ҷмңјл©ҙ getApiKeyлЎң мӢңлҸ„
      if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
        const apiKey = getApiKey("elevenlabs")
        elevenlabsApiKey = apiKey !== undefined ? apiKey : null
      }
      
      if (!elevenlabsApiKey || elevenlabsApiKey.length === 0) {
        alert("ElevenLabs API нӮӨк°Җ н•„мҡ”н•©лӢҲлӢӨ. м„Өм •м—җм„ң API нӮӨлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
        if (isAutoMode) {
          setIsAutoMode(false)
          setAutoModeStep("")
        }
        return
      }
    }

    setIsGeneratingTTS(true)
    shouldStopTTSGeneration.current = false // мӨ‘лӢЁ н”Ңлһҳк·ё мҙҲкё°нҷ”
    ttsAbortControllerRef.current = new AbortController() // мғҲлЎңмҡҙ AbortController мғқм„ұ
    if (isAutoMode) {
      setAutoModeStep("TTS мғқм„ұ мӨ‘...")
      setAutoModeProgress({ current: "5/7", total: 7 })
    }
    
    // м”¬лі„ мІҳлҰ¬ м—¬л¶Җ нҷ•мқё
    const useSceneBasedTTS = decomposedScenes && decomposedScenes.trim().length > 0
    
    if (useSceneBasedTTS) {
      console.log("[TTS] м”¬лі„ TTS мғқм„ұ лӘЁл“ң мӮ¬мҡ©")
      
      // м”¬лі„лЎң нҢҢмӢұ
      const sceneBlocks = decomposedScenes.split(/(?=м”¬\s+\d+)/).filter(block => block.trim().length > 0)
      const parsedScenes: Array<{
        sceneNumber: number
        scenes: Array<{ imageNumber: number; text: string }>
      }> = []
      
      for (const sceneBlock of sceneBlocks) {
        const sceneNumMatch = sceneBlock.match(/м”¬\s+(\d+)/)
        if (!sceneNumMatch) continue
        
        const sceneNum = parseInt(sceneNumMatch[1])
        const sceneImages: Array<{ imageNumber: number; text: string }> = []
        
        const imageRegex = /\[мһҘл©ҙ\s+(\d+)\]\s*\n([\s\S]*?)(?=\[мһҘл©ҙ\s+\d+\]|м”¬\s+\d+|$)/g
        let imageMatch
        
        while ((imageMatch = imageRegex.exec(sceneBlock)) !== null) {
          const imageNum = parseInt(imageMatch[1])
          const imageText = imageMatch[2].trim()
          
          if (imageText) {
            sceneImages.push({
              imageNumber: imageNum,
              text: imageText,
            })
          }
        }
        
        if (sceneImages.length > 0) {
          parsedScenes.push({
            sceneNumber: sceneNum,
            scenes: sceneImages,
          })
        }
      }
      
      console.log(`[TTS] нҢҢмӢұлҗң м”¬ мҲҳ: ${parsedScenes.length}`)
      
      // м”¬ лІҲнҳё мҲңм„ңлҢҖлЎң м •л ¬ (мӨ‘мҡ”: TTS мғқм„ұ мҲңм„ңмҷҖ мқјм№ҳмӢңмјңм•ј н•Ё)
      parsedScenes.sort((a, b) => a.sceneNumber - b.sceneNumber)
      
      parsedScenes.forEach(scene => {
        console.log(`[TTS] м”¬ ${scene.sceneNumber}: ${scene.scenes.length}к°ңмқҳ мһҘл©ҙ л°ңкІ¬`)
        scene.scenes.forEach(img => {
          console.log(`[TTS]   - мһҘл©ҙ ${img.imageNumber}: "${img.text.substring(0, 50)}..."`)
        })
      })
      
      // к°Ғ мһҘл©ҙмқҳ н…ҚмҠӨнҠёлҘј к·ёлҢҖлЎң н•ҳлӮҳмқҳ TTSлЎң мғқм„ұ (л¬ёмһҘ л¶„лҰ¬ м—Ҷмқҙ)
      const sceneTextsForTTS: Array<{ sceneNumber: number; imageNumber: number; text: string; lineId: number }> = []
      let lineIdCounter = 1
      
      for (const parsedScene of parsedScenes) {
        // мһҘл©ҙ лІҲнҳё мҲңм„ңлҢҖлЎң м •л ¬ (мӨ‘мҡ”: TTS мғқм„ұ мҲңм„ңмҷҖ мқјм№ҳмӢңмјңм•ј н•Ё)
        const sortedScenes = [...parsedScene.scenes].sort((a, b) => a.imageNumber - b.imageNumber)
        
        for (const scene of sortedScenes) {
          // к°Ғ мһҘл©ҙмқҳ н…ҚмҠӨнҠёлҘј к·ёлҢҖлЎң мӮ¬мҡ© (л¬ёмһҘ л¶„лҰ¬ м—Ҷмқҙ)
          const text = scene.text.trim()
          
          if (text.length > 0) {
            sceneTextsForTTS.push({
              sceneNumber: parsedScene.sceneNumber,
              imageNumber: scene.imageNumber,
              text: text,
              lineId: lineIdCounter++,
            })
            
            console.log(`[TTS] м”¬ ${parsedScene.sceneNumber} мһҘл©ҙ ${scene.imageNumber} м¶”к°Җ: "${text.substring(0, 50)}..."`)
          }
        }
      }
      
      console.log(`[TTS] мҙқ ${sceneTextsForTTS.length}к°ңмқҳ мһҘл©ҙм—җ лҢҖн•ҙ TTS мғқм„ұ`)
      
      setTtsGenerationProgress({ current: 0, total: sceneTextsForTTS.length })
      setGeneratedAudios([])
      
      let successCount = 0
      let currentProgress = 0
      
      try {
        // к°Ғ мһҘл©ҙлі„лЎң TTS мғқм„ұ
        console.log(`[TTS] TTS мғқм„ұ мӢңмһ‘: мҙқ ${sceneTextsForTTS.length}к°ң л¬ёмһҘ`)
        console.log(`[TTS] мһҘл©ҙлі„ л¶„нҸ¬:`, sceneTextsForTTS.reduce((acc, item) => {
          const key = `м”¬${item.sceneNumber}-мһҘл©ҙ${item.imageNumber}`
          acc[key] = (acc[key] || 0) + 1
          return acc
        }, {} as Record<string, number>))
        
        for (let i = 0; i < sceneTextsForTTS.length; i++) {
          // мӨ‘м§Җ мҡ”мІӯ нҷ•мқё
          if (shouldStopTTSGeneration.current) {
            console.log("[TTS] мӮ¬мҡ©мһҗк°Җ TTS мғқм„ұмқ„ мӨ‘м§Җн–ҲмҠөлӢҲлӢӨ.")
            break
          }
          
          const sceneText = sceneTextsForTTS[i]
          currentProgress++
          setTtsGenerationProgress({ current: currentProgress, total: sceneTextsForTTS.length })
          
          try {
            console.log(`[TTS] [${i + 1}/${sceneTextsForTTS.length}] м”¬ ${sceneText.sceneNumber} мһҘл©ҙ ${sceneText.imageNumber} TTS мғқм„ұ мӢңмһ‘: "${sceneText.text.substring(0, 50)}..."`)
            
            const data = await generateTTSWithRetry(
              { id: sceneText.lineId, text: sceneText.text },
              selectedVoiceId,
              5,
              ttsAbortControllerRef.current?.signal
            )
            
            console.log(`[TTS] [${i + 1}/${sceneTextsForTTS.length}] м”¬ ${sceneText.sceneNumber} мһҘл©ҙ ${sceneText.imageNumber} TTS мғқм„ұ мҷ„лЈҢ`)
            
            setGeneratedAudios((prev) => {
              const newAudios = [
                ...prev,
                {
                  lineId: sceneText.lineId,
                  audioUrl: data.audioUrl,
                  audioBase64: data.audioBase64,
                  alignment: data.alignment || undefined, // alignment лҚ°мқҙн„° м ҖмһҘ
                },
              ]
              console.log(`[TTS] нҳ„мһ¬ мғқм„ұлҗң TTS к°ңмҲҳ: ${newAudios.length}`)
              return newAudios
            })
            successCount++
          } catch (error) {
            const errorMessage = error instanceof Error ? error.message : String(error)
            console.error(`[TTS] [${i + 1}/${sceneTextsForTTS.length}] м”¬ ${sceneText.sceneNumber} мһҘл©ҙ ${sceneText.imageNumber} TTS мғқм„ұ мӢӨнҢЁ:`, errorMessage)
          }
        }
        
        console.log("[TTS] лӘЁл“  мһҘл©ҙлі„ TTS мғқм„ұ мҷ„лЈҢ, м„ұкіө:", successCount, "к°ң / м „мІҙ:", sceneTextsForTTS.length, "к°ң")
        
        if (successCount > 0) {
          console.log("[TTS] TTS мғқм„ұ мҷ„лЈҢ - мӮ¬мқҙл“ңл°” мҷ„лЈҢ н‘ңмӢң м—…лҚ°мқҙнҠё")
          setCompletedSteps((prev) => {
            if (!prev.includes("video")) {
              console.log("[TTS] 'video' лӢЁкі„лҘј мҷ„лЈҢ лӘ©лЎқм—җ м¶”к°Җ")
              return [...prev, "video"]
            }
            console.log("[TTS] 'video' лӢЁкі„лҠ” мқҙлҜё мҷ„лЈҢ лӘ©лЎқм—җ мһҲмқҢ")
            return prev
          })
          
          if (!isAutoMode) {
            if (successCount < sceneTextsForTTS.length) {
              // alert(`${successCount}к°ңмқҳ TTSк°Җ мғқм„ұлҗҳм—ҲмҠөлӢҲлӢӨ. (${sceneTextsForTTS.length - successCount}к°ң мӢӨнҢЁ)\n\nмӢӨнҢЁн•ң н•ӯлӘ©мқҖ лёҢлқјмҡ°м Җ мҪҳмҶ”мқ„ нҷ•мқён•ҙмЈјм„ёмҡ”.`) // мҷ„лЈҢ м•ҢлҰј м ңкұ°
            } else {
              // alert(`${successCount}к°ңмқҳ TTSк°Җ лӘЁл‘җ мғқм„ұлҗҳм—ҲмҠөлӢҲлӢӨ!`) // мҷ„лЈҢ м•ҢлҰј м ңкұ°
            }
          }
          
          if (isAutoMode) {
            console.log("[TTS] мһҗлҸҷнҷ” лӘЁл“ң: мҳҒмғҒ мғқм„ұ мӢңмһ‘")
            setTimeout(() => handleRenderVideo(), 2000)
          }
        } else {
          // мӮ¬мҡ© мӨ‘мқё TTS м„ңл№„мҠӨ нҷ•мқё
          let apiKeyName = "ElevenLabs API нӮӨ"
          if (selectedVoiceId?.startsWith("ttsmaker-")) {
            apiKeyName = "TTSMaker API нӮӨ"
          } else if (selectedVoiceId?.startsWith("supertone-")) {
            apiKeyName = "мҲҳнҚјнҶӨ(SuperTone) API нӮӨ"
          }
          
          const errorMessage = `вқҢ TTS мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.\n\nмӮ¬мҡ© мӨ‘мқё API: ${apiKeyName}\n\nк°ҖлҠҘн•ң мӣҗмқё:\n1. ${apiKeyName}к°Җ мҳ¬л°”лҘҙм§Җ м•ҠмҠөлӢҲлӢӨ\n2. ${apiKeyName}мқҳ мӮ¬мҡ©лҹүмқҙ мҙҲкіјлҗҳм—ҲмҠөлӢҲлӢӨ\n3. л„ӨнҠёмӣҢнҒ¬ м—°кІ° л¬ём ң\n\nн•ҙкІ° л°©лІ•:\n1. м„Өм •м—җм„ң ${apiKeyName}лҘј нҷ•мқён•ҳм„ёмҡ”\n2. API нӮӨк°Җ мҳ¬л°”лҘём§Җ нҷ•мқён•ҳм„ёмҡ”\n3. лёҢлқјмҡ°м Җ мҪҳмҶ”(F12)м—җм„ң мһҗм„ён•ң мҳӨлҘҳлҘј нҷ•мқён•ҙмЈјм„ёмҡ”.`
          alert(errorMessage)
          if (isAutoMode) {
            setIsAutoMode(false)
            setAutoModeStep("")
          }
        }
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : String(error)
        console.error("TTS мғқм„ұ мӢӨнҢЁ:", errorMessage, error)
        
        // мӮ¬мҡ© мӨ‘мқё TTS м„ңл№„мҠӨ нҷ•мқё
        let apiKeyName = "ElevenLabs API нӮӨ"
        if (selectedVoiceId?.startsWith("ttsmaker-")) {
          apiKeyName = "TTSMaker API нӮӨ"
        } else if (selectedVoiceId?.startsWith("supertone-")) {
          apiKeyName = "мҲҳнҚјнҶӨ(SuperTone) API нӮӨ"
        }
        
        // мҳӨлҘҳ л©”мӢңм§Җм—җ API нӮӨ м •ліҙ нҸ¬н•Ё
        let finalErrorMessage = `вқҢ TTS мғқм„ұ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.\n\nмӮ¬мҡ© мӨ‘мқё API: ${apiKeyName}\n\nмҳӨлҘҳ лӮҙмҡ©:\n${errorMessage}`
        
        // API нӮӨ кҙҖл Ё мҳӨлҘҳмқём§Җ нҷ•мқё
        if (errorMessage.toLowerCase().includes("api key") ||
            errorMessage.toLowerCase().includes("api нӮӨ") ||
            errorMessage.toLowerCase().includes("unauthorized") ||
            errorMessage.toLowerCase().includes("мқёмҰқ")) {
          finalErrorMessage += `\n\nн•ҙкІ° л°©лІ•:\n1. м„Өм •м—җм„ң ${apiKeyName}лҘј нҷ•мқён•ҳм„ёмҡ”\n2. API нӮӨк°Җ мҳ¬л°”лҘём§Җ нҷ•мқён•ҳм„ёмҡ”`
        }
        
        alert(finalErrorMessage)
        if (isAutoMode) {
          setIsAutoMode(false)
          setAutoModeStep("")
        }
      } finally {
        setIsGeneratingTTS(false)
        setTtsGenerationProgress({ current: 0, total: 0 })
        shouldStopTTSGeneration.current = false // мӨ‘лӢЁ н”Ңлһҳк·ё мҙҲкё°нҷ”
      }
      
      return
    }
    
    // кё°мЎҙ лЎңм§Ғ (м”¬лі„ TTSк°Җ м•„лӢҢ кІҪмҡ°)
    setTtsGenerationProgress({ current: 0, total: scriptLines.length })
    // кё°мЎҙ мҳӨл””мҳӨ мҙҲкё°нҷ”
    setGeneratedAudios([])

    let successCount = 0

    try {
      for (let i = 0; i < scriptLines.length; i++) {
        // мӨ‘м§Җ мҡ”мІӯ нҷ•мқё
        if (shouldStopTTSGeneration.current) {
          console.log("[TTS] мӮ¬мҡ©мһҗк°Җ TTS мғқм„ұмқ„ мӨ‘м§Җн–ҲмҠөлӢҲлӢӨ.")
          break
        }
        
        const line = scriptLines[i]
        setTtsGenerationProgress({ current: i + 1, total: scriptLines.length })

        try {
          console.log(`[v0] TTS мғқм„ұ мӢңмһ‘ (${i + 1}/${scriptLines.length}): ${line.text.substring(0, 30)}...`)
          
          // мһ¬мӢңлҸ„ лЎңм§Ғмқҙ нҸ¬н•Ёлҗң TTS мғқм„ұ
          const data = await generateTTSWithRetry(
            line,
            selectedVoiceId,
            5,
            ttsAbortControllerRef.current?.signal
          )
          
          console.log(`[v0] TTS мғқм„ұ мҷ„лЈҢ (мӨ„ ${line.id}):`, data.audioUrl ? "URL мһҲмқҢ" : "URL м—ҶмқҢ", data.audioBase64 ? "Base64 мһҲмқҢ" : "Base64 м—ҶмқҢ")

          // TTSк°Җ мғқм„ұлҗҳл©ҙ мҰүмӢң state м—…лҚ°мқҙнҠё (мӢӨмӢңк°„ н‘ңмӢң)
          setGeneratedAudios((prev) => [
            ...prev,
            {
              lineId: line.id,
              audioUrl: data.audioUrl,
              audioBase64: data.audioBase64,
            },
          ])
          successCount++
        } catch (error) {
          const errorMessage = error instanceof Error ? error.message : String(error)
          console.error(`[v0] TTS мғқм„ұ мөңмў… мӢӨнҢЁ (мӨ„ ${line.id}):`, errorMessage)
          console.error(`[v0] мӢӨнҢЁн•ң н…ҚмҠӨнҠё:`, line.text.substring(0, 50) + "...")
          // мӢӨнҢЁн•ҙлҸ„ кі„мҶҚ м§„н–үн•ҳлҗҳ, мӮ¬мҡ©мһҗм—җкІҢ м•ҢлҰј
          if (i === 0) {
            // мІ« лІҲм§ё мӢӨнҢЁ мӢңм—җл§Ң кІҪкі  (лӘЁл“  мӢӨнҢЁлҠ” л§Ҳм§Җл§үм—җ мҡ”м•Ҫ)
            console.warn(`[v0] мІ« лІҲм§ё TTS мғқм„ұ мӢӨнҢЁ. кі„мҶҚ м§„н–үн•©лӢҲлӢӨ...`)
          }
        }
      }

      console.log("[v0] лӘЁл“  TTS мғқм„ұ мҷ„лЈҢ, м„ұкіө:", successCount, "к°ң / м „мІҙ:", scriptLines.length, "к°ң")
      if (successCount > 0) playNotificationSound() // м•ҢлҰјмқҢ мһ¬мғқ

      // TTSк°Җ н•ҳлӮҳлқјлҸ„ мғқм„ұлҗҳм—Ҳмңјл©ҙ мҷ„лЈҢ н‘ңмӢң
      if (successCount > 0) {
        setCompletedSteps((prev) => {
          if (!prev.includes("video")) return [...prev, "video"]
          return prev
        })
        
        if (!isAutoMode) {
          if (successCount < scriptLines.length) {
            // alert(`${successCount}к°ңмқҳ TTSк°Җ мғқм„ұлҗҳм—ҲмҠөлӢҲлӢӨ. (${scriptLines.length - successCount}к°ң мӢӨнҢЁ)\n\nмӢӨнҢЁн•ң н•ӯлӘ©мқҖ лёҢлқјмҡ°м Җ мҪҳмҶ”мқ„ нҷ•мқён•ҙмЈјм„ёмҡ”.`) // мҷ„лЈҢ м•ҢлҰј м ңкұ°
          } else {
            // alert(`${successCount}к°ңмқҳ TTSк°Җ лӘЁл‘җ мғқм„ұлҗҳм—ҲмҠөлӢҲлӢӨ!`) // мҷ„лЈҢ м•ҢлҰј м ңкұ°
          }
        }
        
        // мһҗлҸҷнҷ” лӘЁл“ңмқј л•Ң лӢӨмқҢ лӢЁкі„ мһҗлҸҷ м§„н–ү (мҳҒмғҒ мғқм„ұ)
        if (isAutoMode) {
          console.log("[v0] мһҗлҸҷнҷ” лӘЁл“ң: мҳҒмғҒ мғқм„ұ мӢңмһ‘")
          setTimeout(() => handleRenderVideo(), 2000)
        }
      } else {
        // мӮ¬мҡ© мӨ‘мқё TTS м„ңл№„мҠӨ нҷ•мқё
        let apiKeyName = "ElevenLabs API нӮӨ"
        if (selectedVoiceId?.startsWith("ttsmaker-")) {
          apiKeyName = "TTSMaker API нӮӨ"
        } else if (selectedVoiceId?.startsWith("supertone-")) {
          apiKeyName = "мҲҳнҚјнҶӨ(SuperTone) API нӮӨ"
        }
        
        const errorMessage = `вқҢ TTS мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.\n\nмӮ¬мҡ© мӨ‘мқё API: ${apiKeyName}\n\nк°ҖлҠҘн•ң мӣҗмқё:\n1. ${apiKeyName}к°Җ мҳ¬л°”лҘҙм§Җ м•ҠмҠөлӢҲлӢӨ\n2. ${apiKeyName}мқҳ мӮ¬мҡ©лҹүмқҙ мҙҲкіјлҗҳм—ҲмҠөлӢҲлӢӨ\n3. л„ӨнҠёмӣҢнҒ¬ м—°кІ° л¬ём ң\n\nн•ҙкІ° л°©лІ•:\n1. м„Өм •м—җм„ң ${apiKeyName}лҘј нҷ•мқён•ҳм„ёмҡ”\n2. API нӮӨк°Җ мҳ¬л°”лҘём§Җ нҷ•мқён•ҳм„ёмҡ”\n3. лёҢлқјмҡ°м Җ мҪҳмҶ”(F12)м—җм„ң мһҗм„ён•ң мҳӨлҘҳлҘј нҷ•мқён•ҙмЈјм„ёмҡ”.`
        alert(errorMessage)
        if (isAutoMode) {
          setIsAutoMode(false)
          setAutoModeStep("")
        }
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error)
      console.error("TTS мғқм„ұ мӢӨнҢЁ:", errorMessage, error)
      
      // мӮ¬мҡ© мӨ‘мқё TTS м„ңл№„мҠӨ нҷ•мқё
      let apiKeyName = "ElevenLabs API нӮӨ"
      if (selectedVoiceId?.startsWith("ttsmaker-")) {
        apiKeyName = "TTSMaker API нӮӨ"
      } else if (selectedVoiceId?.startsWith("supertone-")) {
        apiKeyName = "мҲҳнҚјнҶӨ(SuperTone) API нӮӨ"
      }
      
      // мҳӨлҘҳ л©”мӢңм§Җм—җ API нӮӨ м •ліҙ нҸ¬н•Ё
      let finalErrorMessage = `вқҢ TTS мғқм„ұ мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ.\n\nмӮ¬мҡ© мӨ‘мқё API: ${apiKeyName}\n\nмҳӨлҘҳ лӮҙмҡ©:\n${errorMessage}`
      
      // API нӮӨ кҙҖл Ё мҳӨлҘҳмқём§Җ нҷ•мқё
      if (errorMessage.toLowerCase().includes("api key") ||
          errorMessage.toLowerCase().includes("api нӮӨ") ||
          errorMessage.toLowerCase().includes("unauthorized") ||
          errorMessage.toLowerCase().includes("мқёмҰқ")) {
        finalErrorMessage += `\n\nн•ҙкІ° л°©лІ•:\n1. м„Өм •м—җм„ң ${apiKeyName}лҘј нҷ•мқён•ҳм„ёмҡ”\n2. API нӮӨк°Җ мҳ¬л°”лҘём§Җ нҷ•мқён•ҳм„ёмҡ”`
      }
      
      alert(finalErrorMessage)
      if (isAutoMode) {
        setIsAutoMode(false)
        setAutoModeStep("")
      }
    } finally {
      setIsGeneratingTTS(false)
      setTtsGenerationProgress({ current: 0, total: 0 })
    }
  }

  const handleAutoGenerateImages = async () => {
    if (!script) {
      alert("лҢҖліёмқҙ н•„мҡ”н•©лӢҲлӢӨ.")
      return
    }

    setIsLoadingAutoImages(true)
    try {
      console.log("[v0] лҢҖліё л¶„м„қ л°Ҹ мқҙлҜём§Җ мһҗлҸҷ мғқм„ұ мӢңмһ‘")

      // 1. лҢҖліём—җм„ң нӮӨмӣҢл“ң м¶”м¶ң
      const keywords = await extractKeywordsFromScript(script)
      console.log("[v0] м¶”м¶ңлҗң нӮӨмӣҢл“ң:", keywords)

      // 2. к°Ғ нӮӨмӣҢл“ңлЎң мқҙлҜём§Җ кІҖмғү
      const keywordResults = []
      for (let i = 0; i < keywords.length; i++) {
        const item = keywords[i]
        try {
          const response = await fetch(`/api/unsplash-search?query=${encodeURIComponent(item.keyword)}`)
          const data = await response.json()

          if (data.images && data.images.length > 0) {
            const image = data.images[0] // мІ« лІҲм§ё мқҙлҜём§Җ м„ нғқ
            keywordResults.push({
              keyword: item.keyword,
              time: i * 15, // к°Ғ нӮӨмӣҢл“ңл§ҲлӢӨ 15мҙҲ к°„кІ©мңјлЎң мӢңк°„ н• лӢ№
              imageUrl: image.url,
            })
          }
        } catch (error) {
          console.error(`мқҙлҜём§Җ кІҖмғү мӢӨнҢЁ (${item.keyword}):`, error)
        }
      }

      const newAutoImages: AutoImage[] = keywordResults.map((result) => ({
        id: `auto-${Date.now()}-${Math.random()}`,
        url: result.imageUrl,
        keyword: result.keyword,
        startTime: result.time,
        endTime: result.time + 15, // 15мҙҲ лҸҷм•Ҳ н‘ңмӢң
        motion: ["zoom-in", "zoom-out", "pan-left", "pan-right", "static"][
          Math.floor(Math.random() * 5)
        ] as AutoImage["motion"],
      }))

      setAutoImages(newAutoImages)
      console.log("[v0] мһҗлҸҷ мқҙлҜём§Җ мғқм„ұ мҷ„лЈҢ:", newAutoImages.length, "к°ң")
      alert(`${newAutoImages.length}к°ңмқҳ мқҙлҜём§Җк°Җ мһҗлҸҷмңјлЎң м¶”к°Җлҗҳм—ҲмҠөлӢҲлӢӨ!`)
    } catch (error) {
      console.error("мһҗлҸҷ мқҙлҜём§Җ мғқм„ұ мӢӨнҢЁ:", error)
      alert("мһҗлҸҷ мқҙлҜём§Җ мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.")
    } finally {
      setIsLoadingAutoImages(false)
    }
  }

  // CHANGE: handleGenerateVideoлҘј API Route нҳём¶ңлЎң ліҖкІҪ
  const handleGenerateVideo = async () => {
    // Using script and generatedImage as they are defined in the component's state
    if (!script.trim()) {
      alert("лҢҖліёмқ„ мһ…л Ҙн•ҙмЈјм„ёмҡ”.")
      return
    }

    setIsGeneratingVideo(true)
    setGeneratingVideoProgress(0) // Reset progress
    setRenderingStatusMessage("мҳҒмғҒ мғқм„ұ мӨ‘...")

    try {
      console.log("[v0] мҳҒмғҒ мғқм„ұ мӢңмһ‘")

      const response = await fetch("/api/generate-video", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          script: script,
          voiceModel: "ko-KR-Neural2-C",
          autoImages: autoImages,
          userApiKey: userTtsApiKey, // Using the state variable for the API key
          characterImage: generatedImage, // Passing the generated character image
        }),
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || "мҳҒмғҒ мғқм„ұ мӢӨнҢЁ")
      }

      // Stream the response for progress updates
      const reader = response.body?.getReader()
      let receivedLength = 0
      const chunks = []

      while (true) {
        const { done, value } = await reader!.read()
        if (done) break

        const chunkText = new TextDecoder().decode(value, { stream: true })
        chunks.push(chunkText)

        // Process chunks to update progress (this part might need refinement based on API response format)
        try {
          const progressData = JSON.parse(chunkText)
          if (progressData.progress !== undefined) {
            setGeneratingVideoProgress(progressData.progress)
            console.log(`[v0] мҳҒмғҒ мғқм„ұ м§„н–үлҘ : ${progressData.progress}%`)
          }
          if (progressData.audioBase64) {
            receivedLength += progressData.audioBase64.length
          }
        } catch (e) {
          // Ignore if not a progress update JSON
        }
      }

      const fullResponseText = chunks.join("")
      const result = JSON.parse(fullResponseText) // Assume the final response is JSON

      console.log(`[v0] Base64 мҳӨл””мҳӨ лҚ°мқҙн„° мҲҳмӢ , нҒ¬кё°: ${Math.round(receivedLength / 1024)} KB`)

      // Base64лҘј Blob URLлЎң ліҖнҷҳ
      const binaryString = atob(result.audioBase64)
      const bytes = new Uint8Array(binaryString.length)
      for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i)
      }
      const blob = new Blob([bytes], { type: "audio/mpeg" }) // Use mpeg for compatibility
      const audioUrl = URL.createObjectURL(blob)

      console.log("[v0] Blob URL мғқм„ұ мҷ„лЈҢ:", audioUrl)

      const audio = new Audio(audioUrl)
      await new Promise<void>((resolve, reject) => {
        audio.addEventListener("loadedmetadata", () => {
          const realDuration = audio.duration
          console.log(
            `[v0] мӢӨм ң мҳӨл””мҳӨ кёёмқҙ: ${realDuration.toFixed(3)}мҙҲ (м„ңлІ„ кі„мӮ°: ${result.duration.toFixed(3)}мҙҲ)`,
          )

          const scaleFactor = realDuration / result.duration
          console.log(`[v0] мһҗл§ү нғҖмқҙл°Қ мҠӨмјҖмқј нҢ©н„°: ${scaleFactor.toFixed(3)}`)

          const scaledSubtitles = result.subtitles.map((s: any, index: number) => ({
            id: index + 1,
            text: s.text,
            start: s.start * scaleFactor,
            end: s.end * scaleFactor,
          }))

          setVideoData({
            audioUrl,
            subtitles: scaledSubtitles,
            duration: realDuration,
          })

          setCompletedSteps((prev) => [...prev, "video"]) // Mark video step as completed
          resolve()
        })
        audio.addEventListener("error", reject)
      })

      console.log("[v0] мҳҒмғҒ мғқм„ұ мҷ„лЈҢ")
    } catch (error) {
      console.error("[v0] мҳҒмғҒ мғқм„ұ мӢӨнҢЁ:", error)
      alert(`мҳҒмғҒ мғқм„ұм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ: ${error instanceof Error ? error.message : "м•Ң мҲҳ м—ҶлҠ” мҳӨлҘҳ"}`)
    } finally {
      setIsGeneratingVideo(false)
      setGeneratingVideoProgress(0) // Reset progress
      setRenderingStatusMessage("")
    }
  }

