                        const hasCTA = regeneratedScript.includes("мўӢм•„мҡ”мҷҖ кө¬лҸ…") || regeneratedScript.includes("мўӢм•„мҡ”мҷҖ кө¬лҸ…")
                        const scriptWithCTA = hasCTA ? regeneratedScript : regeneratedScript.trim() + ctaText
                        
