                            const sceneNum = parseInt(sceneNumMatch[1])
                            console.log(`[мқҙлҜём§Җ н”„лЎ¬н”„нҠё мғқм„ұ] м”¬ ${sceneNum} мІҳлҰ¬ мӢңмһ‘ (${i + 1}/${totalScenes})`)
                            
                            // м§„н–үлҘ  м—…лҚ°мқҙнҠё
